#define NGPNG_SPRING_TOUCH_NONE 0u
#define NGPNG_SPRING_TOUCH_TOP 1u
#define NGPNG_SPRING_TOUCH_BOTTOM 2u
#define NGPNG_SPRING_TOUCH_LEFT 3u
#define NGPNG_SPRING_TOUCH_RIGHT 4u

static u8 ngpng_tilecol_world(const NgpSceneDef *sc, s16 wx, s16 wy, u8 oob_value)
{
    u16 tx;
    u16 ty;
    if (!sc || !sc->tilecol) return oob_value;
    if (wx < 0 || wy < 0) return oob_value;
    tx = (u16)((u16)wx >> 3u);
    ty = (u16)((u16)wy >> 3u);
    if (tx >= (u16)sc->map_w || ty >= (u16)sc->map_h) return oob_value;
    return sc->tilecol[(u16)(ty * (u16)sc->map_w + tx)];
}

static u8 ngpng_tile_is_ladder(u8 tile)
{
    return (tile == TILE_LADDER) ? 1u : 0u;
}

static u8 ngpng_entity_inst_flags(const NgpSceneDef *sc, u8 entity_idx)
{
    if (!sc || !sc->entity_flags || entity_idx >= sc->entity_count) return 0u;
    return sc->entity_flags[entity_idx];
}

static u8 ngpng_find_first_entity_flags_by_role(const NgpSceneDef *sc, u8 role)
{
    u8 i;
    if (!sc || !sc->entities) return 0u;
    for (i = 0u; i < sc->entity_count; ++i) {
        if (ngpng_entity_role(sc, sc->entities[i].type) != role) continue;
        return ngpng_entity_inst_flags(sc, i);
    }
    return 0u;
}

static void ngpng_clamp_world_rect(const NgpSceneDef *sc, s16 *wx, s16 *wy, u8 w, u8 h)
{
    s16 max_x;
    s16 max_y;
    if (!sc || !wx || !wy) return;
    max_x = (s16)(sc->map_w * 8u);
    max_y = (s16)(sc->map_h * 8u);
    if (max_x < (s16)w) max_x = (s16)w;
    if (max_y < (s16)h) max_y = (s16)h;
    max_x = (s16)(max_x - (s16)w);
    max_y = (s16)(max_y - (s16)h);
    if (*wx < 0) *wx = 0;
    if (*wy < 0) *wy = 0;
    if (*wx > max_x) *wx = max_x;
    if (*wy > max_y) *wy = max_y;
}

static void ngpng_player_clamp_world(const NgpSceneDef *sc, NgpngPlayerActor *p, s16 cam_px, s16 cam_py, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h, s8 render_off_x, s8 render_off_y, u8 frame_w, u8 frame_h)
{
    s16 wx;
    s16 wy;
    s16 min_x;
    s16 min_y;
    s16 max_x;
    s16 max_y;
    if (!sc || !p) return;
    if ((p->flags & NGPNG_ENT_FLAG_CLAMP_MAP) == 0u) return;
    wx = (s16)(cam_px + p->x);
    wy = (s16)(cam_py + p->y);
    (void)render_off_x;
    (void)render_off_y;
    (void)frame_w;
    (void)frame_h;
    min_x = (s16)(-hb_x);
    min_y = (s16)(-hb_y);
    max_x = (s16)((s16)(sc->map_w * 8u) - hb_x - hb_w);
    max_y = (s16)((s16)(sc->map_h * 8u) - hb_y - hb_h);
    if (max_x < min_x) max_x = min_x;
    if (max_y < min_y) max_y = min_y;
    if (wx < min_x) wx = min_x;
    if (wy < min_y) wy = min_y;
    if (wx > max_x) wx = max_x;
    if (wy > max_y) wy = max_y;
    p->x = (s16)(wx - cam_px);
    p->y = (s16)(wy - cam_py);
}

static void ngpng_player_clamp_world_xy(const NgpSceneDef *sc, s16 *wx, s16 *wy, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h, u8 flags)
{
    if ((flags & NGPNG_ENT_FLAG_CLAMP_MAP) == 0u) return;
    if (!sc || !wx || !wy) return;
    {
        s16 min_x = (s16)(-hb_x);
        s16 min_y = (s16)(-hb_y);
        s16 max_x = (s16)((s16)(sc->map_w * 8u) - hb_x - hb_w);
        s16 max_y = (s16)((s16)(sc->map_h * 8u) - hb_y - hb_h);
        if (max_x < min_x) max_x = min_x;
        if (max_y < min_y) max_y = min_y;
        if (*wx < min_x) *wx = min_x;
        if (*wy < min_y) *wy = min_y;
        if (*wx > max_x) *wx = max_x;
        if (*wy > max_y) *wy = max_y;
    }
}

static u8 ngpng_player_touches_ladder(const NgpSceneDef *sc, s16 px, s16 py, u8 frame_w, u8 frame_h)
{
    s16 cx;
    s16 cy0;
    s16 cy1;
    if (!sc) return 0u;
    cx = (s16)(px + (frame_w / 2u));
    cy0 = (s16)(py + 4);
    cy1 = (s16)(py + frame_h - 2);
    return (u8)(ngpng_tile_is_ladder(ngpng_tilecol_world(sc, cx, cy0, TILE_PASS)) || ngpng_tile_is_ladder(ngpng_tilecol_world(sc, cx, cy1, TILE_PASS)));
}

static u8 ngpng_player_find_ladder_below(const NgpSceneDef *sc, s16 wx, s16 wy, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h, s16 *snap_wx)
{
    static const s8 k_offsets[] = { 0, 4, -4, 8, -8 };
    u8 i;
    s16 foot_y;
    s16 center_x;
    if (!sc) return 0u;
    foot_y = (s16)(wy + hb_y + hb_h);
    center_x = (s16)(wx + hb_x + (hb_w / 2u));
    for (i = 0u; i < (u8)(sizeof(k_offsets) / sizeof(k_offsets[0])); ++i) {
        s16 probe_x;
        s16 probe_y;
        u8 tile;
        probe_x = (s16)(center_x + (s16)k_offsets[i]);
        probe_y = (s16)(foot_y + 1);
        tile = ngpng_tilecol_world(sc, probe_x, probe_y, TILE_PASS);
        if (!ngpng_tile_is_ladder(tile)) continue;
        if (snap_wx) {
            s16 tile_center_x;
            tile_center_x = (s16)((s16)(((u16)probe_x >> 3u) * 8u) + 4);
            *snap_wx = (s16)(tile_center_x - hb_x - (hb_w / 2u));
        }
        return 1u;
    }
    return 0u;
}

static u8 ngpng_player_try_ladder_top_exit(const NgpSceneDef *sc, s16 *wx, s16 *wy, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h)
{
    static const s8 k_offsets[] = { 0, 8, -8, 16, -16 };
    u8 i;
    s16 foot_y;
    s16 left_x;
    s16 right_x;
    if (!sc || !wx || !wy) return 0u;
    foot_y = (s16)(*wy + hb_y + hb_h);
    left_x = (s16)(*wx + hb_x + 1);
    right_x = (s16)(*wx + hb_x + ((hb_w > 1u) ? (hb_w - 2u) : 0u));
    for (i = 0u; i < (u8)(sizeof(k_offsets) / sizeof(k_offsets[0])); ++i) {
        s16 floor_yL;
        s16 floor_yR;
        s16 floor_y;
        s16 dx;
        u8 hasL;
        u8 hasR;
        dx = (s16)k_offsets[i];
        hasL = ngpng_floor_probe_world(sc, (s16)(left_x + dx), foot_y, &floor_yL);
        hasR = ngpng_floor_probe_world(sc, (s16)(right_x + dx), foot_y, &floor_yR);
        if (!hasL && !hasR) continue;
        floor_y = hasL ? floor_yL : floor_yR;
        if (hasR && floor_yR < floor_y) floor_y = floor_yR;
        *wx = (s16)(*wx + dx);
        *wy = (s16)(floor_y - hb_y - hb_h);
        return 1u;
    }
    return 0u;
}

static u8 ngpng_player_spring_touch_side(const NgpSceneDef *sc, s16 px, s16 py, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h, s8 vx, s8 vy)
{
    s16 x0;
    s16 x1;
    s16 xm;
    s16 y0;
    s16 y1;
    s16 ym;
    u8 hit_top;
    u8 hit_bottom;
    u8 hit_left;
    u8 hit_right;
    if (!sc) return NGPNG_SPRING_TOUCH_NONE;
    x0 = (s16)(px + hb_x + 1);
    x1 = (s16)(px + hb_x + ((hb_w > 0u) ? (hb_w - 1u) : 0u) - 1);
    xm = (s16)(px + hb_x + (hb_w / 2u));
    y0 = (s16)(py + hb_y + 1);
    y1 = (s16)(py + hb_y + ((hb_h > 0u) ? hb_h : 1u));
    ym = (s16)(py + hb_y + (hb_h / 2u));
    if (x1 < x0) x1 = x0;
    if (y1 < y0) y1 = y0;
    hit_top = (u8)(ngpng_tile_is_spring(ngpng_tilecol_world(sc, x0, (s16)(y0 - 1), TILE_PASS)) || ngpng_tile_is_spring(ngpng_tilecol_world(sc, x1, (s16)(y0 - 1), TILE_PASS)) || ngpng_tile_is_spring(ngpng_tilecol_world(sc, xm, (s16)(y0 - 1), TILE_PASS)));
    hit_bottom = (u8)(ngpng_tile_is_spring(ngpng_tilecol_world(sc, x0, y1, TILE_PASS)) || ngpng_tile_is_spring(ngpng_tilecol_world(sc, x1, y1, TILE_PASS)) || ngpng_tile_is_spring(ngpng_tilecol_world(sc, xm, y1, TILE_PASS)));
    hit_left = (u8)(ngpng_tile_is_spring(ngpng_tilecol_world(sc, (s16)(x0 - 1), y0, TILE_PASS)) || ngpng_tile_is_spring(ngpng_tilecol_world(sc, (s16)(x0 - 1), ym, TILE_PASS)) || ngpng_tile_is_spring(ngpng_tilecol_world(sc, (s16)(x0 - 1), (s16)(y1 - 1), TILE_PASS)));
    hit_right = (u8)(ngpng_tile_is_spring(ngpng_tilecol_world(sc, (s16)(x1 + 1), y0, TILE_PASS)) || ngpng_tile_is_spring(ngpng_tilecol_world(sc, (s16)(x1 + 1), ym, TILE_PASS)) || ngpng_tile_is_spring(ngpng_tilecol_world(sc, (s16)(x1 + 1), (s16)(y1 - 1), TILE_PASS)));
    if (hit_bottom && (vy >= 0 || (!hit_left && !hit_right))) return NGPNG_SPRING_TOUCH_BOTTOM;
    if (hit_top && (vy <= 0 || (!hit_left && !hit_right))) return NGPNG_SPRING_TOUCH_TOP;
    if (hit_left && (vx <= 0 || !hit_right)) return NGPNG_SPRING_TOUCH_LEFT;
    if (hit_right && (vx >= 0 || !hit_left)) return NGPNG_SPRING_TOUCH_RIGHT;
    if (hit_bottom) return NGPNG_SPRING_TOUCH_BOTTOM;
    if (hit_top) return NGPNG_SPRING_TOUCH_TOP;
    if (hit_left) return NGPNG_SPRING_TOUCH_LEFT;
    if (hit_right) return NGPNG_SPRING_TOUCH_RIGHT;
    return NGPNG_SPRING_TOUCH_NONE;
}

static void ngpng_player_apply_tile_effects(const NgpSceneDef *sc, s16 px, s16 py, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h, s8 *vx, s8 *vy, u8 *on_ground, u8 *coyote, u8 *hp, u8 *invul)
{
    s16 x0;
    s16 x1;
    s16 xm;
    s16 y0;
    s16 y1;
    s16 ym;
    u8 t0;
    u8 t1;
    u8 t2;
    u8 t3;
    u8 t4;
    u8 hit_damage;
    u8 hit_fire;
    u8 hit_void;
    u8 spring_touch;
    u8 spring_dir;
    u8 spring_force;
    u8 dmg;
    if (!hp || !invul || !vx || !vy || !on_ground || !coyote || *hp == 0u) return;
    x0 = (s16)(px + hb_x + 1);
    x1 = (s16)(px + hb_x + ((hb_w > 0u) ? (hb_w - 1u) : 0u) - 1);
    xm = (s16)(px + hb_x + (hb_w / 2u));
    y0 = (s16)(py + hb_y + 1);
    y1 = (s16)(py + hb_y + ((hb_h > 0u) ? (hb_h - 1u) : 0u) - 1);
    ym = (s16)(py + hb_y + (hb_h / 2u));
    if (x1 < x0) x1 = x0;
    if (y1 < y0) y1 = y0;
    t0 = ngpng_tilecol_world(sc, x0, y0, TILE_PASS);
    t1 = ngpng_tilecol_world(sc, x1, y0, TILE_PASS);
    t2 = ngpng_tilecol_world(sc, x0, y1, TILE_PASS);
    t3 = ngpng_tilecol_world(sc, x1, y1, TILE_PASS);
    t4 = ngpng_tilecol_world(sc, xm, ym, TILE_PASS);
    hit_void = (u8)(ngpng_tile_is_void(t0) || ngpng_tile_is_void(t1) || ngpng_tile_is_void(t2) || ngpng_tile_is_void(t3) || ngpng_tile_is_void(t4));
    if (hit_void) {
        if (sc && sc->void_instant) {
            *hp = 0u;
            return;
        }
        if (*invul != 0u) return;
        dmg = (u8)(sc ? sc->void_damage : 1u);
        if (dmg == 0u) return;
        *hp = (dmg >= *hp) ? 0u : (u8)(*hp - dmg);
        if (sc) *invul = sc->hazard_invul;
        return;
    }
    if (*invul == 0u) {
        hit_damage = (u8)(ngpng_tile_is_damage(t0) || ngpng_tile_is_damage(t1) || ngpng_tile_is_damage(t2) || ngpng_tile_is_damage(t3) || ngpng_tile_is_damage(t4));
        hit_fire = (u8)(ngpng_tile_is_fire(t0) || ngpng_tile_is_fire(t1) || ngpng_tile_is_fire(t2) || ngpng_tile_is_fire(t3) || ngpng_tile_is_fire(t4));
        if (hit_fire || hit_damage) {
            if (hit_fire) {
                dmg = (u8)((sc && sc->fire_damage != 0u) ? sc->fire_damage : 0u);
            } else {
                dmg = (u8)((sc && sc->hazard_damage != 0u) ? sc->hazard_damage : 0u);
            }
            if (dmg != 0u) {
                *hp = (dmg >= *hp) ? 0u : (u8)(*hp - dmg);
                if (sc) *invul = sc->hazard_invul;
            }
        }
    }
    if (!sc) return;
    spring_force = sc->spring_force;
    if (spring_force == 0u) return;
    spring_touch = ngpng_player_spring_touch_side(sc, px, py, hb_x, hb_y, hb_w, hb_h, *vx, *vy);
    if (spring_touch == NGPNG_SPRING_TOUCH_NONE) return;
    spring_dir = sc->spring_dir;
    if (spring_dir == (u8)NGPNG_SPRING_DIR_OPPOSITE_TOUCH) {
        if (spring_touch == NGPNG_SPRING_TOUCH_BOTTOM) spring_dir = (u8)NGPNG_SPRING_DIR_UP;
        else if (spring_touch == NGPNG_SPRING_TOUCH_TOP) spring_dir = (u8)NGPNG_SPRING_DIR_DOWN;
        else if (spring_touch == NGPNG_SPRING_TOUCH_LEFT) spring_dir = (u8)NGPNG_SPRING_DIR_RIGHT;
        else if (spring_touch == NGPNG_SPRING_TOUCH_RIGHT) spring_dir = (u8)NGPNG_SPRING_DIR_LEFT;
    }
    if (spring_dir == (u8)NGPNG_SPRING_DIR_UP) {
        *vy = (s8)(-(s8)spring_force);
    } else if (spring_dir == (u8)NGPNG_SPRING_DIR_DOWN) {
        *vy = (s8)spring_force;
    } else if (spring_dir == (u8)NGPNG_SPRING_DIR_LEFT) {
        *vx = (s8)(-(s8)spring_force);
        if (*vy > 0) *vy = 0;
    } else if (spring_dir == (u8)NGPNG_SPRING_DIR_RIGHT) {
        *vx = (s8)spring_force;
        if (*vy > 0) *vy = 0;
    }
    *on_ground = 0u;
    *coyote = 0u;
}

static u8 ngpng_player_touches_door_tile(const NgpSceneDef *sc, s16 px, s16 py, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h)
{
    s16 x0;
    s16 x1;
    s16 xm;
    s16 y0;
    s16 y1;
    u8 t0;
    u8 t1;
    u8 t2;
    if (!sc) return 0u;
    x0 = (s16)(px + hb_x + 1);
    x1 = (s16)(px + hb_x + ((hb_w > 0u) ? (hb_w - 1u) : 0u) - 1);
    if (x1 < x0) x1 = x0;
    xm = (s16)(px + hb_x + (hb_w / 2u));
    y0 = (s16)(py + hb_y + (hb_h / 2u));
    y1 = (s16)(py + hb_y + hb_h);
    t0 = ngpng_tilecol_world(sc, x0, y0, TILE_PASS);
    t1 = ngpng_tilecol_world(sc, x1, y0, TILE_PASS);
    t2 = ngpng_tilecol_world(sc, xm, y1, TILE_PASS);
    return (u8)(ngpng_tile_is_door(t0) || ngpng_tile_is_door(t1) || ngpng_tile_is_door(t2));
}

static u8 ngpng_region_goto_scene_target(const NgpSceneDef *sc, u8 region_idx)
{
    u8 i;
    if (!sc || !sc->triggers || region_idx >= sc->region_count) return 0xFFu;
    for (i = 0; i < sc->trigger_count; ++i) {
        const NgpngTrigger *t = &sc->triggers[i];
        if (t->action != TRIG_ACT_GOTO_SCENE) continue;
        if (t->region != region_idx) continue;
        return t->a0;
    }
    return 0xFFu;
}

static void ngpng_reset_trigger_state(u8 *trig_state, u8 *trig_enabled, u8 *reg_state)
{
    u8 i;
    for (i = 0; i < (u8)NGPNG_AUTORUN_MAX_TRIG; ++i) {
        trig_state[i] = 0u;
        trig_enabled[i] = 1u;
    }
    for (i = 0; i < (u8)NGPNG_AUTORUN_MAX_REG; ++i) reg_state[i] = 0u;
}

static void ngpng_reset_scene_scroll_state(const NgpSceneDef *sc, u8 *forced_scroll_on, u8 *scroll_paused, s16 *scroll_speed_x, s16 *scroll_speed_y)
{
    if (!sc) {
        *forced_scroll_on = 0u;
        *scroll_paused = 0u;
        *scroll_speed_x = 0;
        *scroll_speed_y = 0;
        return;
    }
    *forced_scroll_on = sc->forced_scroll ? 1u : 0u;
    *scroll_paused = 0u;
    *scroll_speed_x = sc->scroll_speed_x;
    *scroll_speed_y = sc->scroll_speed_y;
}

/* Global flags (0=clear, !=0=set) and u8 variables.
 * Persist across scene transitions — zero-initialised at power-on.
 * Addressable via trigger a0 (action) or region field (condition). */
#define NGPNG_FLAG_COUNT 8u
#define NGPNG_VAR_COUNT  8u
static u8 s_ngpng_flags[NGPNG_FLAG_COUNT];
static u8 s_ngpng_vars[NGPNG_VAR_COUNT];

static u8 ngpng_trigger_cond_met(u8 cond, u8 region, u16 value, const u8 *in_reg, const u8 *prev_reg, u8 reg_n, u16 tx, u16 ty, u16 timer, u8 next_wave, u8 player_hp, u8 lives, u8 enemy_active_count, u16 collectible_count, u16 pad_pressed, u8 player_jump_started)
{
    u8 fire = 0u;
    if (cond == TRIG_ENTER_REGION || cond == TRIG_LEAVE_REGION) {
        if (region < reg_n) {
            u8 in = in_reg[region];
            if (cond == TRIG_ENTER_REGION) fire = (u8)(in && !prev_reg[region]);
            if (cond == TRIG_LEAVE_REGION) fire = (u8)(!in && prev_reg[region]);
        }
    } else if (cond == TRIG_CAM_X_GE) {
        fire = ((u16)tx >= value) ? 1u : 0u;
    } else if (cond == TRIG_CAM_Y_GE) {
        fire = ((u16)ty >= value) ? 1u : 0u;
    } else if (cond == TRIG_TIMER_GE) {
        fire = (timer >= value) ? 1u : 0u;
    } else if (cond == TRIG_WAVE_GE) {
        fire = ((u16)next_wave >= value) ? 1u : 0u;
    } else if (cond == TRIG_BTN_A) {
        fire = (pad_pressed & PAD_A) ? 1u : 0u;
    } else if (cond == TRIG_BTN_B) {
        fire = (pad_pressed & PAD_B) ? 1u : 0u;
    } else if (cond == TRIG_BTN_A_B) {
        fire = ((pad_pressed & PAD_A) && (pad_pressed & PAD_B)) ? 1u : 0u;
    } else if (cond == TRIG_BTN_UP) {
        fire = (pad_pressed & PAD_UP) ? 1u : 0u;
    } else if (cond == TRIG_BTN_DOWN) {
        fire = (pad_pressed & PAD_DOWN) ? 1u : 0u;
    } else if (cond == TRIG_BTN_LEFT) {
        fire = (pad_pressed & PAD_LEFT) ? 1u : 0u;
    } else if (cond == TRIG_BTN_RIGHT) {
        fire = (pad_pressed & PAD_RIGHT) ? 1u : 0u;
    } else if (cond == TRIG_BTN_OPT) {
        fire = (pad_pressed & PAD_OPTION) ? 1u : 0u;
    } else if (cond == TRIG_ON_JUMP) {
        fire = player_jump_started ? 1u : 0u;
    } else if (cond == TRIG_WAVE_CLEARED) {
        fire = (((u16)next_wave > value) && (enemy_active_count == 0u)) ? 1u : 0u;
    } else if (cond == TRIG_HEALTH_LE) {
        fire = (player_hp <= (u8)value) ? 1u : 0u;
    } else if (cond == TRIG_HEALTH_GE) {
        fire = (player_hp >= (u8)value) ? 1u : 0u;
    } else if (cond == TRIG_ENEMY_COUNT_LE) {
        fire = (enemy_active_count <= (u8)value) ? 1u : 0u;
    } else if (cond == TRIG_LIVES_LE) {
        fire = (lives <= (u8)value) ? 1u : 0u;
    } else if (cond == TRIG_LIVES_GE) {
        fire = (lives >= (u8)value) ? 1u : 0u;
    } else if (cond == TRIG_COLLECTIBLE_COUNT_GE) {
        fire = (collectible_count >= value) ? 1u : 0u;
    } else if (cond == TRIG_FLAG_SET) {
        fire = (region < NGPNG_FLAG_COUNT && s_ngpng_flags[region] != 0u) ? 1u : 0u;
    } else if (cond == TRIG_FLAG_CLEAR) {
        fire = (region < NGPNG_FLAG_COUNT && s_ngpng_flags[region] == 0u) ? 1u : 0u;
    } else if (cond == TRIG_VARIABLE_GE) {
        fire = (region < NGPNG_VAR_COUNT && s_ngpng_vars[region] >= (u8)value) ? 1u : 0u;
    } else if (cond == TRIG_VARIABLE_EQ) {
        fire = (region < NGPNG_VAR_COUNT && s_ngpng_vars[region] == (u8)value) ? 1u : 0u;
    }
    if (fire && (cond == TRIG_BTN_A || cond == TRIG_BTN_B || cond == TRIG_BTN_A_B || cond == TRIG_BTN_UP || cond == TRIG_BTN_DOWN || cond == TRIG_BTN_LEFT || cond == TRIG_BTN_RIGHT || cond == TRIG_BTN_OPT)) {
        if (region != 255u) fire = (region < reg_n) ? in_reg[region] : 0u;
    }
    return fire;
}

static void ngpng_fx_clear(NgpngFx *fx, u8 *active_count, u8 *alloc_idx)
{
    u8 i;
    for (i = 0; i < (u8)NGPNG_AUTORUN_MAX_FX; ++i) {
        fx[i].active = 0u;
        fx[i].visible = 0u;
        fx[i].last_sx = (s16)-32768;
        fx[i].last_sy = (s16)-32768;
        fx[i].last_tile = 0xFFFFu;
    }
    *active_count = 0u;
    *alloc_idx = 0u;
}

static s8 ngpng_step_toward(s16 cur, s16 dst, s8 step)
{
    if (cur < dst - step) return step;
    if (cur > dst + step) return (s8)(-step);
    return 0;
}

static void ngpng_fx_kill(NgpngFx *fx, u8 *active_count, u8 idx)
{
    if (!fx[idx].active) return;
    fx[idx].active = 0u;
    ngpng_fx_hide(fx, idx);
    if (*active_count > 0u) *active_count = (u8)(*active_count - 1u);
}

static void ngpng_fx_spawn(NgpngFx *fx, u8 *active_count, u8 *alloc_idx, u8 fx_type, s16 world_x, s16 world_y)
{
    u8 k;
    if (fx_type == 0xFFu) return;
    if (*active_count >= (u8)NGPNG_AUTORUN_MAX_FX) return;
    for (k = 0; k < (u8)NGPNG_AUTORUN_MAX_FX; ++k) {
        u8 i = (u8)(*alloc_idx + k);
        if (i >= (u8)NGPNG_AUTORUN_MAX_FX) i = (u8)(i - (u8)NGPNG_AUTORUN_MAX_FX);
        if (!fx[i].active) {
            fx[i].active = 1u;
            fx[i].visible = 0u;
            fx[i].type = fx_type;
            fx[i].anim = 0u;
            fx[i].last_frame = 0xFFu;
            fx[i].pal = 0u;
            fx[i].flags = (u8)SPR_FRONT;
            fx[i].world_x = world_x;
            fx[i].world_y = world_y;
            fx[i].ox = 0;
            fx[i].oy = 0;
            fx[i].last_sx = (s16)-32768;
            fx[i].last_sy = (s16)-32768;
            fx[i].last_tile = 0xFFFFu;
            *active_count = (u8)(*active_count + 1u);
            *alloc_idx = (u8)(i + 1u);
            if (*alloc_idx >= (u8)NGPNG_AUTORUN_MAX_FX) *alloc_idx = 0u;
            return;
        }
    }
}

static void ngpng_fx_update(const NgpSceneDef *sc, NgpngFx *fx, u8 *fx_active_count, s16 cam_px, s16 cam_py)
{
    u8 i;
    u8 processed = 0u;
    if (*fx_active_count == 0u) return;
    for (i = 0; i < (u8)NGPNG_AUTORUN_MAX_FX; ++i) {
        if (!fx[i].active) continue;
        processed = (u8)(processed + 1u);
        fx[i].anim = (u8)(fx[i].anim + 1u);
        if (fx[i].anim > 18u) {
            ngpng_fx_kill(fx, fx_active_count, i);
            continue;
        }
        ngpng_fx_sync(sc, fx, i, cam_px, cam_py);
        if (processed >= *fx_active_count) break;
    }
}

static u8 ngpng_sprite_mspr_draw(u8 spr_start, s16 x, s16 y, const NgpcMetasprite *def, u8 flags)
{
    u8 i;
    u8 count;
    u8 group_hflip = (flags & SPR_HFLIP) ? 1u : 0u;
    u8 group_vflip = (flags & SPR_VFLIP) ? 1u : 0u;
    u8 priority = (u8)(flags & 0x18u);
    if (!def) return 0u;
    if (spr_start >= 64u) return 0u;
    count = def->count;
    if ((u16)spr_start + count > 64u) count = (u8)(64u - spr_start);
    for (i = 0; i < count; ++i) {
        const MsprPart *p = &def->parts[i];
        s16 px;
        s16 py;
        u8 part_flags = p->flags;
        if (group_hflip) px = (s16)(x + (s16)(def->width - 8u) - (s16)p->ox);
        else px = (s16)(x + (s16)p->ox);
        if (group_vflip) py = (s16)(y + (s16)(def->height - 8u) - (s16)p->oy);
        else py = (s16)(y + (s16)p->oy);
        if (group_hflip) part_flags ^= SPR_HFLIP;
        if (group_vflip) part_flags ^= SPR_VFLIP;
        part_flags = (u8)((part_flags & (u8)~0x18u) | priority);
        if (px < -7 || px > 159 || py < -7 || py > 151) ngpc_sprite_hide((u8)(spr_start + i));
        else ngpc_sprite_set((u8)(spr_start + i), (u8)((u16)px & 0xFFu), (u8)((u16)py & 0xFFu), p->tile, p->pal, part_flags);
    }
    return count;
}

static void ngpng_sprite_hide_range(u8 start, u8 count)
{
    u8 i;
    for (i = 0; i < count; ++i) {
        if ((u16)start + i >= 64u) break;
        ngpc_sprite_hide((u8)(start + i));
    }
}

static void ngpng_player_layer_sync(u8 spr_start, s16 x, s16 y, u8 frame_idx, const MsprAnimFrame *anim, u8 anim_count, u8 *visible, s16 *last_x, s16 *last_y, u8 *last_frame)
{
    const NgpcMetasprite *def;
    u8 i;
    if (!anim || anim_count == 0u) return;
    frame_idx = (u8)(frame_idx % anim_count);
    def = anim[frame_idx].frame;
    if (!def) return;
    if (!*visible) {
        ngpng_sprite_mspr_draw(spr_start, x, y, def, (u8)SPR_FRONT);
        *visible = 1u;
        *last_frame = frame_idx;
        *last_x = x;
        *last_y = y;
        return;
    }
    if (*last_frame != frame_idx) {
        for (i = 0; i < def->count; ++i) {
            const MsprPart *p = &def->parts[i];
            ngpc_sprite_set_tile((u8)(spr_start + i), p->tile);
        }
        *last_frame = frame_idx;
    }
    if (*last_x != x || *last_y != y) {
        for (i = 0; i < def->count; ++i) {
            const MsprPart *p = &def->parts[i];
            s16 px = (s16)(x + (s16)p->ox);
            s16 py = (s16)(y + (s16)p->oy);
            if (px < -7 || px > 159 || py < -7 || py > 151) ngpc_sprite_hide((u8)(spr_start + i));
            else ngpc_sprite_move((u8)(spr_start + i), (u8)((u16)px & 0xFFu), (u8)((u16)py & 0xFFu));
        }
        *last_x = x;
        *last_y = y;
    }
}

static u8 ngpng_entity_sprite_info(const NgpSceneDef *sc, u8 type, u8 frame_idx, u16 *tile, u8 *pal, u8 *flags, s16 *ox, s16 *oy)
{
    const NgpcMetasprite *def;
    const MsprPart *part;
    if (!sc->resolve_entity_frame) return 0u;
    def = sc->resolve_entity_frame(type, frame_idx);
    if (!def || def->count == 0u) return 0u;
    part = &def->parts[0];
    *tile = part->tile;
    *pal = part->pal;
    *flags = (u8)(SPR_FRONT | (u8)part->flags);
    *ox = (s16)part->ox;
    *oy = (s16)part->oy;
    return 1u;
}

static void ngpng_props_clear(NgpngPropActor *props)
{
    u8 i;
    for (i = 0u; i < (u8)NGPNG_AUTORUN_MAX_PROPS; ++i) {
        props[i].active = 0u;
        props[i].visible = 0u;
        props[i].role = NGPNG_ROLE_PROP;
        props[i].type = 0u;
        props[i].src_idx = 0xFFu;
        props[i].anim = 0u;
        props[i].moving = 0u;
        props[i].paused = 0u;
        props[i].path_idx = 0xFFu;
        props[i].path_step = 0u;
        props[i].data = 0u;
        props[i].state = 0u;
        props[i].bump_timer = 0u;
        props[i].hb_x = 0u;
        props[i].hb_y = 0u;
        props[i].hb_w = 8u;
        props[i].hb_h = 8u;
        props[i].world_x = 0;
        props[i].world_y = 0;
        props[i].prev_world_x = 0;
        props[i].prev_world_y = 0;
        props[i].home_y = 0;
        props[i].target_x = 0;
        props[i].target_y = 0;
    }
}

static u8 ngpng_prop_find_by_src(const NgpngPropActor *props, u8 prop_count, u8 src_idx)
{
    u8 i;
    for (i = 0u; i < prop_count && i < (u8)NGPNG_AUTORUN_MAX_PROPS; ++i) {
        if (props[i].active && props[i].src_idx == src_idx) return i;
    }
    return 0xFFu;
}

static void ngpng_props_set_anim_by_type(NgpngPropActor *props, u8 prop_count, u8 type, u8 anim_state)
{
    u8 i;
    for (i = 0u; i < prop_count && i < (u8)NGPNG_AUTORUN_MAX_PROPS; ++i) {
        if (!props[i].active || props[i].type != type) continue;
        props[i].anim = (u8)((anim_state & 0x03u) << 3u);
    }
}

static void ngpng_props_reset_scene(const NgpSceneDef *sc, NgpngPropActor *props, u8 *prop_count)
{
    u8 i;
    u8 n = 0u;
    ngpng_props_clear(props);
    *prop_count = 0u;
    ngpng_sprite_hide_range((u8)NGPNG_AUTORUN_PROP_SPR_BASE, (u8)NGPNG_AUTORUN_PROP_SPR_COUNT);
    if (!sc || !sc->entities) return;
    for (i = 0u; i < sc->entity_count; ++i) {
        const NgpngEnt *src = &sc->entities[i];
        u8 role;
        if (n >= (u8)NGPNG_AUTORUN_MAX_PROPS) break;
        role = ngpng_entity_role(sc, src->type);
        if (role == NGPNG_ROLE_PLAYER || role == NGPNG_ROLE_ENEMY || role == NGPNG_ROLE_TRIGGER) continue;
        props[n].active = 1u;
        props[n].visible = 1u;
        props[n].role = role;
        props[n].type = src->type;
        props[n].src_idx = i;
        props[n].anim = 0u;
        props[n].moving = 0u;
        props[n].paused = 0u;
        props[n].path_idx = 0xFFu;
        props[n].path_step = 0u;
        props[n].data = src->data;
        props[n].state = 0u;
        props[n].bump_timer = 0u;
        props[n].ent_flags = sc->entity_flags ? sc->entity_flags[i] : 0u;
        props[n].hb_x = ngpng_type_s8(sc->hitbox_x, sc->type_role_count, src->type, 0);
        props[n].hb_y = ngpng_type_s8(sc->hitbox_y, sc->type_role_count, src->type, 0);
        props[n].hb_w = ngpng_type_u8(sc->hitbox_w, sc->type_role_count, src->type, 8u);
        props[n].hb_h = ngpng_type_u8(sc->hitbox_h, sc->type_role_count, src->type, 8u);
        props[n].world_x = (s16)(src->x * 8);
        props[n].world_y = (s16)(src->y * 8);
        props[n].prev_world_x = props[n].world_x;
        props[n].prev_world_y = props[n].world_y;
        props[n].home_y = props[n].world_y;
        props[n].target_x = props[n].world_x;
        props[n].target_y = props[n].world_y;
        if (sc->entity_paths && i < sc->entity_count) {
            u8 assigned = sc->entity_paths[i];
            if (assigned != 0xFFu && assigned < sc->path_count) props[n].path_idx = assigned;
        }
        ++n;
    }
    *prop_count = n;
}

static void ngpng_props_apply_path_step(const NgpSceneDef *sc, NgpngPropActor *prop)
{
    u8 pi;
    u8 plen;
    u16 off;
    const NgpngPoint *pt;
    s16 dst_x;
    s16 dst_y;
    if (!sc || !prop) return;
    if (prop->path_idx == 0xFFu || prop->path_idx >= sc->path_count) return;
    if (!sc->path_points || !sc->path_offsets || !sc->path_lengths) return;
    pi = prop->path_idx;
    plen = sc->path_lengths[pi];
    if (plen == 0u) return;
    off = sc->path_offsets[pi];
    if (prop->path_step >= plen) prop->path_step = 0u;
    pt = &sc->path_points[off + prop->path_step];
    dst_x = (s16)(pt->x * 8);
    dst_y = (s16)(pt->y * 8);
    prop->world_x = (s16)(prop->world_x + ngpng_step_toward(prop->world_x, dst_x, 1));
    prop->world_y = (s16)(prop->world_y + ngpng_step_toward(prop->world_y, dst_y, 1));
    if (prop->ent_flags & NGPNG_ENT_FLAG_CLAMP_MAP) ngpng_clamp_world_rect(sc, &prop->world_x, &prop->world_y, prop->hb_w, prop->hb_h);
    if (prop->world_x == dst_x && prop->world_y == dst_y) {
        prop->path_step = (u8)(prop->path_step + 1u);
        if (prop->path_step >= plen) {
            if (sc->path_flags && sc->path_flags[pi]) prop->path_step = 0u;
            else {
                prop->path_step = (u8)(plen - 1u);
                prop->paused = 1u;
            }
        }
    }
}

static void ngpng_props_update(const NgpSceneDef *sc, NgpngPropActor *props, u8 prop_count)
{
    u8 i;
    for (i = 0u; i < prop_count && i < (u8)NGPNG_AUTORUN_MAX_PROPS; ++i) {
        if (!props[i].active) continue;
        props[i].anim = (u8)(props[i].anim + 1u);
        props[i].prev_world_x = props[i].world_x;
        props[i].prev_world_y = props[i].world_y;
        if (props[i].role == NGPNG_ROLE_BLOCK) {
            props[i].home_y = props[i].target_y;
            if (props[i].bump_timer > 0u) {
                u8 bt = props[i].bump_timer;
                if (bt >= 5u) props[i].world_y = (s16)(props[i].home_y - 3);
                else if (bt >= 3u) props[i].world_y = (s16)(props[i].home_y - 1);
                else props[i].world_y = props[i].home_y;
                props[i].bump_timer = (u8)(bt - 1u);
                continue;
            }
            props[i].world_y = props[i].home_y;
            continue;
        }
        if (props[i].path_idx != 0xFFu && !props[i].paused) {
            ngpng_props_apply_path_step(sc, &props[i]);
            continue;
        }
        if (!props[i].moving) continue;
        if (props[i].world_x < props[i].target_x) {
            s16 nx = (s16)(props[i].world_x + 2);
            props[i].world_x = (nx > props[i].target_x) ? props[i].target_x : nx;
        } else if (props[i].world_x > props[i].target_x) {
            s16 nx = (s16)(props[i].world_x - 2);
            props[i].world_x = (nx < props[i].target_x) ? props[i].target_x : nx;
        }
        if (props[i].world_y < props[i].target_y) {
            s16 ny = (s16)(props[i].world_y + 2);
            props[i].world_y = (ny > props[i].target_y) ? props[i].target_y : ny;
        } else if (props[i].world_y > props[i].target_y) {
            s16 ny = (s16)(props[i].world_y - 2);
            props[i].world_y = (ny < props[i].target_y) ? props[i].target_y : ny;
        }
        if (props[i].world_x == props[i].target_x && props[i].world_y == props[i].target_y) props[i].moving = 0u;
        if (props[i].ent_flags & NGPNG_ENT_FLAG_CLAMP_MAP) ngpng_clamp_world_rect(sc, &props[i].world_x, &props[i].world_y, props[i].hb_w, props[i].hb_h);
    }
}

static void ngpng_player_apply_platform_delta(const NgpngPropActor *props, u8 prop_count, u8 rider_idx, s16 *px, s16 *py)
{
    const NgpngPropActor *p;
    if (!px || !py) return;
    if (rider_idx == 0xFFu || rider_idx >= prop_count || rider_idx >= (u8)NGPNG_AUTORUN_MAX_PROPS) return;
    p = &props[rider_idx];
    if (!p->active || !p->visible || p->role != NGPNG_ROLE_PLATFORM) return;
    *px = (s16)(*px + (p->world_x - p->prev_world_x));
    *py = (s16)(*py + (p->world_y - p->prev_world_y));
}

static u8 ngpng_player_resolve_platforms(const NgpngPropActor *props, u8 prop_count, s16 prev_world_x, s16 prev_world_y, s16 cam_px, s16 cam_py, s16 *px, s16 *py, s8 *vy, u8 *on_ground, u8 *coyote, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h)
{
    u8 i;
    u8 best = 0xFFu;
    s16 best_top = 32767;
    s16 world_x;
    s16 world_y;
    s16 prev_left;
    s16 prev_right;
    s16 prev_foot;
    s16 foot;
    if (!px || !py || !vy || !on_ground) return 0xFFu;
    if (*vy < 0) return 0xFFu;
    world_x = (s16)(cam_px + *px);
    world_y = (s16)(cam_py + *py);
    prev_left = (s16)(prev_world_x + hb_x + 1);
    prev_right = (s16)(prev_world_x + hb_x + ((hb_w > 1u) ? (hb_w - 2u) : 0u));
    prev_foot = (s16)(prev_world_y + hb_y + hb_h);
    foot = (s16)(world_y + hb_y + hb_h);
    for (i = 0u; i < prop_count && i < (u8)NGPNG_AUTORUN_MAX_PROPS; ++i) {
        const NgpngPropActor *p = &props[i];
        s16 plat_left;
        s16 plat_right;
        s16 plat_top;
        if (!p->active || !p->visible || p->role != NGPNG_ROLE_PLATFORM) continue;
        plat_left = (s16)(p->world_x + p->hb_x);
        plat_right = (s16)(plat_left + p->hb_w);
        plat_top = (s16)(p->world_y + p->hb_y);
        if (prev_right <= plat_left || prev_left >= plat_right) continue;
        if (prev_foot > (s16)(plat_top + 4)) continue;
        if (foot < (s16)(plat_top - 2) || foot > (s16)(plat_top + 8)) continue;
        if (plat_top < best_top) { best_top = plat_top; best = i; }
    }
    if (best != 0xFFu) {
        const NgpngPropActor *p = &props[best];
        *py = (s16)((p->world_y + p->hb_y) - hb_y - hb_h - cam_py);
        *vy = 0;
        *on_ground = 1u;
        if (coyote) *coyote = 0u;
    }
    return best;
}

static void ngpng_player_collect_items(const NgpSceneDef *sc, NgpngPropActor *props, u8 prop_count, s16 player_world_x, s16 player_world_y, s8 player_hb_x, s8 player_hb_y, u8 player_hb_w, u8 player_hb_h, u16 *score, u8 *hp, u8 hp_max, u16 *collectible_count)
{
    u8 i;
    s16 ax;
    s16 ay;
    if (!sc || !props) return;
    ax = (s16)(player_world_x + player_hb_x);
    ay = (s16)(player_world_y + player_hb_y);
    for (i = 0u; i < prop_count && i < (u8)NGPNG_AUTORUN_MAX_PROPS; ++i) {
        u8 score_gain;
        u8 heal_gain;
        u8 mult;
        s16 bx;
        s16 by;
        if (!props[i].active || !props[i].visible || props[i].role != NGPNG_ROLE_ITEM) continue;
        bx = (s16)(props[i].world_x + props[i].hb_x);
        by = (s16)(props[i].world_y + props[i].hb_y);
        if (!ngpng_rects_overlap(ax, ay, player_hb_w, player_hb_h, bx, by, props[i].hb_w, props[i].hb_h)) continue;
        mult = props[i].data ? props[i].data : 1u;
        score_gain = ngpng_type_u8(sc->type_score, sc->type_role_count, props[i].type, 0u);
        heal_gain = ngpng_type_u8(sc->type_hp, sc->type_role_count, props[i].type, 0u);
        if (score_gain == 0u && heal_gain == 0u) score_gain = 1u;
        if (score && score_gain > 0u) *score = (u16)(*score + ((u16)score_gain * (u16)mult * 10u));
        if (hp && heal_gain > 0u && *hp < hp_max) {
            u16 next_hp = (u16)(*hp + (u16)(heal_gain * mult));
            *hp = (next_hp > hp_max) ? hp_max : (u8)next_hp;
        }
        if (collectible_count) *collectible_count = (u16)(*collectible_count + (u16)mult);
        props[i].active = 0u;
        props[i].visible = 0u;
    }
}

static void ngpng_player_bump_blocks(const NgpSceneDef *sc, NgpngPropActor *props, u8 prop_count, s16 prev_world_x, s16 prev_world_y, s16 cam_px, s16 cam_py, s16 *px, s16 *py, s8 *vy, s8 hb_x, s8 hb_y, u8 hb_w, u8 hb_h, u16 *score, u8 *hp, u8 hp_max, u16 *collectible_count)
{
    u8 i;
    s16 world_x;
    s16 world_y;
    s16 left;
    s16 right;
    s16 prev_head;
    s16 head;
    if (!sc || !props || !px || !py || !vy) return;
    if (*vy >= 0) return;
    world_x = (s16)(cam_px + *px);
    world_y = (s16)(cam_py + *py);
    left = (s16)(world_x + hb_x + 1);
    right = (s16)(world_x + hb_x + ((hb_w > 1u) ? (hb_w - 2u) : 0u));
    prev_head = (s16)(prev_world_y + hb_y);
    head = (s16)(world_y + hb_y);
    for (i = 0u; i < prop_count && i < (u8)NGPNG_AUTORUN_MAX_PROPS; ++i) {
        s16 bx0;
        s16 bx1;
        s16 by0;
        s16 by1;
        u8 block_kind;
        if (!props[i].active || !props[i].visible || props[i].role != NGPNG_ROLE_BLOCK) continue;
        bx0 = (s16)(props[i].world_x + props[i].hb_x);
        bx1 = (s16)(bx0 + props[i].hb_w);
        by0 = (s16)(props[i].world_y + props[i].hb_y);
        by1 = (s16)(by0 + props[i].hb_h);
        if (right <= bx0 || left >= bx1) continue;
        if (prev_head < by1 - 2 || head > by1 + 2) continue;
        *py = (s16)(by1 - hb_y - cam_py);
        *vy = 0;
        props[i].bump_timer = 6u;
        block_kind = props[i].data;
        if (block_kind == 1u) {
            props[i].active = 0u;
            props[i].visible = 0u;
        } else if (block_kind == 2u) {
            if (props[i].state == 0u) {
                u8 score_gain = ngpng_type_u8(sc->type_score, sc->type_role_count, props[i].type, 1u);
                u8 heal_gain = ngpng_type_u8(sc->type_hp, sc->type_role_count, props[i].type, 0u);
                if (score) *score = (u16)(*score + ((u16)score_gain * 10u));
                if (collectible_count) *collectible_count = (u16)(*collectible_count + 1u);
                if (hp && heal_gain > 0u && *hp < hp_max) {
                    u16 next_hp = (u16)(*hp + heal_gain);
                    *hp = (next_hp > hp_max) ? hp_max : (u8)next_hp;
                }
                props[i].state = 1u;
                props[i].anim = 8u;
            }
        }
        return;
    }
}

static void ngpng_props_draw(const NgpSceneDef *sc, NgpngPropActor *props, u8 prop_count, s16 cam_px, s16 cam_py)
{
    u8 i;
    u8 spr = (u8)NGPNG_AUTORUN_PROP_SPR_BASE;
    u8 spr_end = (u8)(NGPNG_AUTORUN_PROP_SPR_BASE + NGPNG_AUTORUN_PROP_SPR_COUNT);
    if (!NGPNG_AUTORUN_ENT_PREVIEW || !sc || !sc->draw_entity_anim || NGPNG_AUTORUN_PROP_SPR_COUNT == 0u) return;
    ngpng_sprite_hide_range((u8)NGPNG_AUTORUN_PROP_SPR_BASE, (u8)NGPNG_AUTORUN_PROP_SPR_COUNT);
    for (i = 0u; i < prop_count && i < (u8)NGPNG_AUTORUN_MAX_PROPS; ++i) {
        u8 next;
        s16 sx;
        s16 sy;
        if (!props[i].active || !props[i].visible) continue;
        if (spr >= spr_end) break;
        sx = (s16)(props[i].world_x - cam_px);
        sy = (s16)(props[i].world_y - cam_py);
        next = sc->draw_entity_anim(spr, props[i].type, (u8)((props[i].anim >> 3) & 0x03u), sx, sy);
        if (next <= spr) next = (u8)(spr + 1u);
        if (next > spr_end) break;
        spr = next;
    }
}

static void ngpng_fx_hide(NgpngFx *fx, u8 idx)
{
    u8 slot = (u8)(NGPNG_AUTORUN_FX_SPR_BASE + idx);
    if (fx[idx].visible) ngpc_sprite_hide(slot);
    fx[idx].visible = 0u;
    fx[idx].last_sx = (s16)-32768;
    fx[idx].last_sy = (s16)-32768;
    fx[idx].last_tile = 0xFFFFu;
}

static void ngpng_fx_sync(const NgpSceneDef *sc, NgpngFx *fx, u8 idx, s16 cam_px, s16 cam_py)
{
    NgpngFx *f = &fx[idx];
    u8 slot = (u8)(NGPNG_AUTORUN_FX_SPR_BASE + idx);
    u8 frame_idx;
    s16 sx;
    s16 sy;
    s16 px;
    s16 py;
    u16 tile;
    if (!f->active) { ngpng_fx_hide(fx, idx); return; }
    if (slot >= (u8)NGPNG_AUTORUN_HUD_SPR_BASE) return;
    frame_idx = (u8)(f->anim / 6u);
    tile = f->last_tile;
    if (f->last_frame != frame_idx || f->last_tile == 0xFFFFu) {
        if (!ngpng_entity_sprite_info(sc, f->type, frame_idx, &tile, &f->pal, &f->flags, &f->ox, &f->oy)) { ngpng_fx_hide(fx, idx); return; }
        f->last_frame = frame_idx;
    }
    sx = (s16)(f->world_x - cam_px);
    sy = (s16)(f->world_y - cam_py);
    px = (s16)(sx + f->ox);
    py = (s16)(sy + f->oy);
    if (!f->visible) {
        ngpc_sprite_set(slot, (u8)((u16)px & 0xFFu), (u8)((u16)py & 0xFFu), tile, f->pal, f->flags);
        f->visible = 1u;
        f->last_tile = tile;
        f->last_sx = px;
        f->last_sy = py;
    } else {
        if (f->last_tile != tile) { ngpc_sprite_set_tile(slot, tile); f->last_tile = tile; }
        if (f->last_sx != px || f->last_sy != py) {
            ngpc_sprite_move(slot, (u8)((u16)px & 0xFFu), (u8)((u16)py & 0xFFu));
            f->last_sx = px;
            f->last_sy = py;
        }
    }
}

static void ngpng_hud_reset(void)
{
    s_hud_visible = 0u;
    s_hud_last_score = 0xFFFFu;
    s_hud_last_hp = 0xFFu;
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 0, "                    ");
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 1, "                    ");
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 2, "                    ");
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 16, "                    ");
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 17, "                    ");
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 18, "                    ");
}

static void ngpng_hud_u16(char *dst, u16 v)
{
    dst[0] = (char)('0' + ((v / 10000u) % 10u));
    dst[1] = (char)('0' + ((v / 1000u) % 10u));
    dst[2] = (char)('0' + ((v / 100u) % 10u));
    dst[3] = (char)('0' + ((v / 10u) % 10u));
    dst[4] = (char)('0' + (v % 10u));
    dst[5] = 0;
}

static u16 ngpng_hud_metric_value(u8 metric, u16 score, u8 hp, u8 lives, u8 continues_left, u16 collectibles, u16 timer_frames)
{
    switch (metric) {
        case NGPNG_HUD_METRIC_HP: return (u16)hp;
        case NGPNG_HUD_METRIC_SCORE: return score;
        case NGPNG_HUD_METRIC_COLLECT: return collectibles;
        case NGPNG_HUD_METRIC_TIMER: return (u16)(timer_frames / 60u);
        case NGPNG_HUD_METRIC_LIVES: return (u16)lives;
        case NGPNG_HUD_METRIC_CONTINUES: return (u16)continues_left;
        default: return 0u;
    }
}

static void ngpng_hud_format_value(char *dst, u16 value, u8 digits, u8 zero_pad)
{
    u8 i;
    if (digits == 0u) digits = 1u;
    if (digits > 6u) digits = 6u;
    for (i = 0u; i < digits; ++i) {
        dst[(u8)(digits - 1u - i)] = (char)('0' + (value % 10u));
        value = (u16)(value / 10u);
    }
    dst[digits] = 0;
    if (!zero_pad) {
        for (i = 0u; i + 1u < digits; ++i) {
            if (dst[i] != '0') break;
            dst[i] = ' ';
        }
    }
}

static u8 ngpng_hud_value_font_ready(const NgpSceneDef *sc, const char *buf, u8 digits)
{
    u8 i;
    if (!sc || !sc->hud_digit_types || !sc->draw_entity_anim) return 0u;
    for (i = 0u; i < digits; ++i) {
        char ch = buf[i];
        if (ch == ' ') continue;
        if (ch < '0' || ch > '9') return 0u;
        if (sc->hud_digit_types[(u8)(ch - '0')] == 255u) return 0u;
    }
    return 1u;
}

static void ngpng_hud_draw_value(const NgpSceneDef *sc, u8 *spr_io, const NgpngHudItem *it, u16 value)
{
    char buf[7];
    u8 digits;
    u8 i;
    if (!it) return;
    digits = it->digits;
    if (digits == 0u) digits = 1u;
    if (digits > 6u) digits = 6u;
    ngpng_hud_format_value(buf, value, digits, (u8)((it->flags & NGPNG_HUD_FLAG_ZERO_PAD) ? 1u : 0u));
    if (ngpng_hud_value_font_ready(sc, buf, digits)) {
        u8 spr = *spr_io;
        for (i = 0u; i < digits; ++i) {
            u8 next;
            char ch = buf[i];
            if (ch == ' ') continue;
            if (spr >= 64u) break;
            next = sc->draw_entity_anim(spr, sc->hud_digit_types[(u8)(ch - '0')], 0u, (s16)(((u16)it->x + i) * 8u), (s16)((u16)it->y * 8u));
            if (next <= spr || next > 64u) break;
            spr = next;
        }
        *spr_io = spr;
    } else {
        ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, it->x, it->y, "      ");
        ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, it->x, it->y, buf);
    }
}

static void ngpng_hud_sync(const NgpSceneDef *sc, u8 hud_flags, u8 hud_pos, u8 hud_font_mode, u16 score, u8 hp, u8 lives, u8 continues_left, u16 collectibles, u16 timer_frames, u8 game_over, u8 stage_clear)
{
    char num[6];
    u16 time_sec = (u16)(timer_frames / 60u);
    u8 pos0 = 0u;
    u8 pos1 = 0u;
    u8 row0 = (hud_pos == 1u) ? 16u : 0u;
    u8 row1 = (u8)(row0 + 1u);
    u8 row2 = (u8)(row0 + 2u);
    ngpng_sprite_hide_range((u8)NGPNG_AUTORUN_HUD_SPR_BASE, (u8)(64u - NGPNG_AUTORUN_HUD_SPR_BASE));
    if (!s_hud_visible) {
        s_hud_visible = 1u;
    }
    s_hud_line0[0] = 0;
    s_hud_line1[0] = 0;
    if (hud_font_mode == 0u && (hud_flags & 2u)) {
        s_hud_line0[pos0++] = 'H'; s_hud_line0[pos0++] = 'P'; s_hud_line0[pos0++] = ':'; s_hud_line0[pos0++] = (char)('0' + (hp % 10u));
    }
    if (hud_font_mode == 0u && (hud_flags & 1u)) {
        ngpng_hud_u16(num, score);
        if (pos0) s_hud_line0[pos0++] = ' ';
        s_hud_line0[pos0++] = 'S'; s_hud_line0[pos0++] = ':';
        s_hud_line0[pos0++] = num[0]; s_hud_line0[pos0++] = num[1]; s_hud_line0[pos0++] = num[2]; s_hud_line0[pos0++] = num[3]; s_hud_line0[pos0++] = num[4];
    }
    if (hud_font_mode == 0u && (hud_flags & 16u)) {
        if (pos0) s_hud_line0[pos0++] = ' ';
        s_hud_line0[pos0++] = 'L'; s_hud_line0[pos0++] = ':';
        s_hud_line0[pos0++] = (char)('0' + ((lives / 10u) % 10u)); s_hud_line0[pos0++] = (char)('0' + (lives % 10u));
    }
    s_hud_line0[pos0] = 0;
    if (hud_font_mode == 0u && (hud_flags & 4u)) {
        ngpng_hud_u16(num, collectibles);
        s_hud_line1[pos1++] = 'C'; s_hud_line1[pos1++] = ':';
        s_hud_line1[pos1++] = num[0]; s_hud_line1[pos1++] = num[1]; s_hud_line1[pos1++] = num[2]; s_hud_line1[pos1++] = num[3]; s_hud_line1[pos1++] = num[4];
    }
    if (hud_font_mode == 0u && (hud_flags & 8u)) {
        ngpng_hud_u16(num, time_sec);
        if (pos1) s_hud_line1[pos1++] = ' ';
        s_hud_line1[pos1++] = 'T'; s_hud_line1[pos1++] = ':';
        s_hud_line1[pos1++] = num[0]; s_hud_line1[pos1++] = num[1]; s_hud_line1[pos1++] = num[2]; s_hud_line1[pos1++] = num[3]; s_hud_line1[pos1++] = num[4];
    }
    s_hud_line1[pos1] = 0;
    if (game_over) {
        s_hud_state_line[0] = 'G'; s_hud_state_line[1] = 'A'; s_hud_state_line[2] = 'M'; s_hud_state_line[3] = 'E';
        s_hud_state_line[4] = ' '; s_hud_state_line[5] = 'O'; s_hud_state_line[6] = 'V'; s_hud_state_line[7] = 'E'; s_hud_state_line[8] = 'R';
        s_hud_state_line[9] = ' '; s_hud_state_line[10] = 'B'; s_hud_state_line[11] = '=';
        if (continues_left > 0u) {
            s_hud_state_line[12] = 'C'; s_hud_state_line[13] = 'O'; s_hud_state_line[14] = 'N'; s_hud_state_line[15] = 'T';
            s_hud_state_line[16] = (char)('0' + ((continues_left / 10u) % 10u));
            s_hud_state_line[17] = (char)('0' + (continues_left % 10u));
            s_hud_state_line[18] = ' '; s_hud_state_line[19] = 0;
        } else {
            s_hud_state_line[12] = 'R'; s_hud_state_line[13] = 'E'; s_hud_state_line[14] = 'T'; s_hud_state_line[15] = 'R'; s_hud_state_line[16] = 'Y';
            s_hud_state_line[17] = ' '; s_hud_state_line[18] = ' '; s_hud_state_line[19] = 0;
        }
        ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, row2, s_hud_state_line);
    } else if (stage_clear) {
        ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, row2, "STAGE CLEAR B=RETRY ");
    } else {
        ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, row2, "                    ");
    }
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, row0, "                    ");
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, row1, "                    ");
    if (hud_font_mode == 0u) {
        ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, row0, s_hud_line0);
        ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, row1, s_hud_line1);
    } else if (sc && sc->hud_items && sc->hud_item_count > 0u) {
        u8 i;
        u8 spr = (u8)NGPNG_AUTORUN_HUD_SPR_BASE;
        for (i = 0u; i < sc->hud_item_count; ++i) {
            const NgpngHudItem *it = &sc->hud_items[i];
            if (it->kind == NGPNG_HUD_KIND_ICON) {
                if (!sc->draw_entity_anim || it->type == 255u || spr >= 64u) continue;
                spr = sc->draw_entity_anim(spr, it->type, 0u, (s16)((u16)it->x * 8u), (s16)((u16)it->y * 8u));
                if (spr == 0u || spr > 64u) break;
            } else if (it->kind == NGPNG_HUD_KIND_VALUE) {
                ngpng_hud_draw_value(sc, &spr, it, ngpng_hud_metric_value(it->metric, score, hp, lives, continues_left, collectibles, timer_frames));
            }
        }
    }
    s_hud_last_score = score;
    s_hud_last_hp = hp;
}

#if NGPNG_AUTORUN_DEBUG_OVERLAY
static void print_sfx_line(u8 id)
{
    /* "SFX id: 000" */
    s_sfx_line[0] = 'S'; s_sfx_line[1] = 'F'; s_sfx_line[2] = 'X';
    s_sfx_line[3] = ' '; s_sfx_line[4] = 'i'; s_sfx_line[5] = 'd';
    s_sfx_line[6] = ':'; s_sfx_line[7] = ' ';
    s_sfx_line[8]  = (char)('0' + (id / 100u));
    s_sfx_line[9]  = (char)('0' + ((id / 10u) % 10u));
    s_sfx_line[10] = (char)('0' + (id % 10u));
    s_sfx_line[11] = 0;
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 7, s_sfx_line);
}

static void print_trig_line(u8 idx)
{
    /* "TRIG: 000" */
    s_trig_line[0] = 'T'; s_trig_line[1] = 'R'; s_trig_line[2] = 'I'; s_trig_line[3] = 'G';
    s_trig_line[4] = ':'; s_trig_line[5] = ' ';
    s_trig_line[6] = (char)('0' + (idx / 100u));
    s_trig_line[7] = (char)('0' + ((idx / 10u) % 10u));
    s_trig_line[8] = (char)('0' + (idx % 10u));
    s_trig_line[9] = 0;
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 8, s_trig_line);
}

static void print_scene_line(u8 scene_idx)
{
    /* "Scene: 00 id" */
    const char *id = 0;
    u8 i = 0;
    if (scene_idx < (u8)NGP_SCENE_COUNT) id = g_ngp_scenes[scene_idx].id;
    s_scene_line[0] = 'S'; s_scene_line[1] = 'c'; s_scene_line[2] = 'e'; s_scene_line[3] = 'n'; s_scene_line[4] = 'e';
    s_scene_line[5] = ':'; s_scene_line[6] = ' ';
    s_scene_line[7] = (char)('0' + (scene_idx / 10u));
    s_scene_line[8] = (char)('0' + (scene_idx % 10u));
    s_scene_line[9] = ' ';
    if (!id) id = "?";
    for (i = 0; i < 16u; ++i) {
        char ch = id[i];
        if (!ch) break;
        s_scene_line[10u + i] = ch;
    }
    s_scene_line[10u + i] = 0;
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 2, s_scene_line);
}

#endif /* NGPNG_AUTORUN_DEBUG_OVERLAY */

/* ---- Player runtime state (one NgpngPlayerActor per player sprite) ---- */
static NgpngPlayerActor s_magician_iddle;
static s16 s_magician_iddle_last_x = (s16)-32768;
static s16 s_magician_iddle_last_y = (s16)-32768;
static u8 s_magician_iddle_last_frame = 0xFFu;
static u8 s_magician_iddle_visible = 0u;

void main(void)
{
    u16 tx = 0, ty = 0;
    u8 sfx_id = 0;
    u16 timer = 0;
    u16 score = 0;
    u16 collectible_count = 0u;
    u8  shake_timer = 0u; /* screen shake: countdown in frames */
    u8  shake_amp   = 2u; /* shake amplitude in pixels */
#if NGPNG_AUTORUN_SCORE_HUD
    u16 best_score = 0u;
    u8  flash_saved = 0u; /* prevents repeated saves during a single game_over */
#endif
    u8 cur_scene = 0;
    u8 next_wave = 0;
    u8 player_type = 0xFFu;
    s8 player_hb_x = 0;
    s8 player_hb_y = 0;
    u8 player_hb_w = 8u;
    u8 player_hb_h = 8u;
    s8 player_body_x = 0;
    s8 player_body_y = 0;
    u8 player_body_w = 8u;
    u8 player_body_h = 8u;
    s8 player_render_off_x = 0;
    s8 player_render_off_y = 0;
    u8 player_frame_w = 8u;
    u8 player_frame_h = 8u;
    u8 player_bullet_type = 0xFFu;
    u8 explosion_type = 0xFFu;
    u16 player_bullet_tile = 0u;
    u8 player_bullet_pal = 0u;
    u8 player_bullet_flags = (u8)SPR_FRONT;
    s8 player_bullet_hb_x = 0;
    s8 player_bullet_hb_y = 0;
    u8 player_bullet_hb_w = 8u;
    u8 player_bullet_hb_h = 8u;
    u8 player_bullet_damage = 1u;
    s8 player_bullet_kb_x = 0;
    s8 player_bullet_kb_y = 0;
    s16 player_bullet_ox = 0;
    s16 player_bullet_oy = 0;
    u8 player_bullet_ready = 0u;
    u8 player_hp = 3u;
    u8 player_hp_max = 3u;
    u8 player_invul = 0u;
    u8 player_jump_started = 0u;
    u8 game_over = 0u;
    u8 stage_clear = 0u;
    u8 lives = 0u;
    u8 continues_left = 0u;
    u8 respawn_timer = 0u;
    u8 fire_cd = 0u;
    u8 player_form = 0u;
    u8 player_form_count = 0u;
    u8 player_form_mode = 0u;
    u8 player_ent_flags = 0u;
    u8 checkpoint_scene = 0xFFu;
    u8 checkpoint_region = 0xFFu;
    u8 player_platform = 0xFFu;
    u8 player_shots_active = 0u;
    u8 player_shots_alloc = 0u;
    u8 enemy_active_count = 0u;
    u8 enemy_alloc_idx = 0u;
    u8 enemy_bullets_active = 0u;
    u8 enemy_bullets_alloc = 0u;
    u8 fx_active_count = 0u;
    u8 fx_alloc_idx = 0u;
    s16 cam_px = 0, cam_py = 0;
    NgpngFx fx[NGPNG_AUTORUN_MAX_FX];
    NgpngPropActor props[NGPNG_AUTORUN_MAX_PROPS];
    u8 prop_count = 0u;
    static u8 s_trig_fired[NGPNG_AUTORUN_MAX_TRIG];
    static u8 s_trig_enabled[NGPNG_AUTORUN_MAX_TRIG];
    static u8 s_reg_prev[NGPNG_AUTORUN_MAX_REG];
    u8 runtime_forced_scroll = 0u;
    u8 runtime_scroll_paused = 0u;
    s16 runtime_scroll_speed_x = 0;
    s16 runtime_scroll_speed_y = 0;

    ngpc_init();
    ngpc_load_sysfont();

    /* Ensure we do not start on a blank white screen. */
    ngpc_gfx_scroll(GFX_SCR1, 0, 0);
    ngpc_gfx_scroll(GFX_SCR2, 0, 0);
    ngpc_gfx_clear(GFX_SCR1);
    ngpc_gfx_clear(GFX_SCR2);
    ngpc_sprite_hide_all();
    ngpng_hud_reset();
    ngpc_gfx_set_bg_color(RGB(0,0,0));
    ngpc_gfx_set_palette(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, RGB(0,0,0), RGB(15,15,15), RGB(10,10,10), RGB(6,6,6));
    ngpc_gfx_set_palette(GFX_SPR, (u8)NGPNG_AUTORUN_HUD_PAL, RGB(0,0,0), RGB(15,15,15), RGB(10,10,10), RGB(6,6,6));
#if NGPNG_AUTORUN_DEBUG_OVERLAY
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 0, "NGPNG Boot...");
#endif
    ngpc_vsync();
#if defined(NGP_ENABLE_SOUND) && (NGP_ENABLE_SOUND)
    /* Sound driver init (needed for BGM autostart). */
    #if !NGPNG_DIAG_SKIP_SOUND_INIT
    Sounds_Init();
    #endif
#endif
#if NGPNG_AUTORUN_SCORE_HUD
    /* Flash save: load best score if a valid save exists. */
    {
        u8 flash_buf[8];
        ngpc_flash_init();
        if (ngpc_flash_exists()) {
            ngpc_flash_load(flash_buf);
            best_score = (u16)(((u16)flash_buf[4] << 8) | flash_buf[5]);
        }
    }
#endif

#if defined(NGP_SCENE_LVL_1_IDX)
    cur_scene = (u8)NGP_SCENE_LVL_1_IDX;
#else
    cur_scene = (u8)NGP_SCENE_START_INDEX;
#endif
    if (cur_scene >= (u8)NGP_SCENE_COUNT) cur_scene = 0;
    #if !NGPNG_DIAG_SKIP_SCENE_ENTER
    g_ngp_scenes[cur_scene].enter();
    #endif
    cam_px = (s16)(g_ngp_scenes[cur_scene].cam_tile_x * 8u);
    cam_py = (s16)(g_ngp_scenes[cur_scene].cam_tile_y * 8u);
    ngpng_apply_camera_constraints(&g_ngp_scenes[cur_scene], &cam_px, &cam_py);
    ngpng_queue_plane_stream(&g_ngp_scenes[cur_scene], cam_px, cam_py);
    ngpng_apply_plane_scroll(&g_ngp_scenes[cur_scene], cam_px, cam_py);
    tx = (u16)(cam_px >> 3);
    ty = (u16)(cam_py >> 3);
    ngpng_fx_clear(fx, &fx_active_count, &fx_alloc_idx);
    ngpng_props_reset_scene(&g_ngp_scenes[cur_scene], props, &prop_count);
    player_form = 0u;
    player_form_mode = 0u;
    player_form_count = ngpng_count_types_by_role(&g_ngp_scenes[cur_scene], NGPNG_ROLE_PLAYER);
    player_ent_flags = ngpng_find_first_entity_flags_by_role(&g_ngp_scenes[cur_scene], NGPNG_ROLE_PLAYER);
    ngpng_player_apply_form(&g_ngp_scenes[cur_scene], player_form, &player_type, &player_hb_x, &player_hb_y, &player_hb_w, &player_hb_h, &player_body_x, &player_body_y, &player_body_w, &player_body_h, &player_render_off_x, &player_render_off_y, &player_frame_w, &player_frame_h, &player_hp, &player_hp_max, 1u);
    player_bullet_type = ngpng_find_first_type_by_role(&g_ngp_scenes[cur_scene], NGPNG_ROLE_ITEM);
    explosion_type = ngpng_find_first_type_by_role(&g_ngp_scenes[cur_scene], NGPNG_ROLE_PROP);
    player_bullet_ready = 0u;
    if (player_bullet_type != 0xFFu && ngpng_entity_sprite_info(&g_ngp_scenes[cur_scene], player_bullet_type, 0u, &player_bullet_tile, &player_bullet_pal, &player_bullet_flags, &player_bullet_ox, &player_bullet_oy)) player_bullet_ready = 1u;
    if (player_bullet_type != 0xFFu) {
        player_bullet_hb_x = ngpng_type_attack_s8(g_ngp_scenes[cur_scene].attack_hitbox_x, g_ngp_scenes[cur_scene].hitbox_x, g_ngp_scenes[cur_scene].type_role_count, player_bullet_type, 0);
        player_bullet_hb_y = ngpng_type_attack_s8(g_ngp_scenes[cur_scene].attack_hitbox_y, g_ngp_scenes[cur_scene].hitbox_y, g_ngp_scenes[cur_scene].type_role_count, player_bullet_type, 0);
        player_bullet_hb_w = ngpng_type_attack_u8(g_ngp_scenes[cur_scene].attack_hitbox_w, g_ngp_scenes[cur_scene].hitbox_w, g_ngp_scenes[cur_scene].type_role_count, player_bullet_type, 8u);
        player_bullet_hb_h = ngpng_type_attack_u8(g_ngp_scenes[cur_scene].attack_hitbox_h, g_ngp_scenes[cur_scene].hitbox_h, g_ngp_scenes[cur_scene].type_role_count, player_bullet_type, 8u);
        player_bullet_damage = ngpng_type_attack_u8(g_ngp_scenes[cur_scene].attack_hitbox_damage, g_ngp_scenes[cur_scene].type_damage, g_ngp_scenes[cur_scene].type_role_count, player_bullet_type, 1u);
        player_bullet_kb_x = ngpng_type_attack_s8(g_ngp_scenes[cur_scene].attack_hitbox_kb_x, 0, g_ngp_scenes[cur_scene].type_role_count, player_bullet_type, 0);
        player_bullet_kb_y = ngpng_type_attack_s8(g_ngp_scenes[cur_scene].attack_hitbox_kb_y, 0, g_ngp_scenes[cur_scene].type_role_count, player_bullet_type, 0);
    }
    player_invul = 0u;
    game_over = 0u;
    stage_clear = 0u;
    lives = g_ngp_scenes[cur_scene].start_lives;
    continues_left = g_ngp_scenes[cur_scene].start_continues;
    respawn_timer = 0u;
    fire_cd = 0u;
    checkpoint_scene = 0xFFu;
    checkpoint_region = 0xFFu;
    player_platform = 0xFFu;
    collectible_count = 0u;
    ngpng_reset_trigger_state(s_trig_fired, s_trig_enabled, s_reg_prev);
    ngpng_reset_scene_scroll_state(&g_ngp_scenes[cur_scene], &runtime_forced_scroll, &runtime_scroll_paused, &runtime_scroll_speed_x, &runtime_scroll_speed_y);

    /* ---- Player actor init (spawn at screen center) ---- */
    {
        s16 spawn_x;
        s16 spawn_y;
        ngpng_place_player_on_respawn(&g_ngp_scenes[cur_scene], (checkpoint_scene == cur_scene) ? checkpoint_region : 0xFFu, &cam_px, &cam_py, &spawn_x, &spawn_y);
        tx = (u16)(cam_px >> 3);
        ty = (u16)(cam_py >> 3);
        MAGICIAN_IDDLE_CTRL_INIT(s_magician_iddle, spawn_x, spawn_y);
        s_magician_iddle.flags = player_ent_flags;
        ngpng_player_clamp_world(&g_ngp_scenes[cur_scene], &s_magician_iddle, cam_px, cam_py, player_body_x, player_body_y, player_body_w, player_body_h, player_render_off_x, player_render_off_y, player_frame_w, player_frame_h);
        s_magician_iddle_visible = 0u;
        s_magician_iddle_last_x = (s16)-32768;
        s_magician_iddle_last_y = (s16)-32768;
        s_magician_iddle_last_frame = 0xFFu;
    }

#if NGPNG_AUTORUN_DEBUG_OVERLAY
    /* Debug UI palette: choose a palette slot you keep free in your assets. */
    ngpc_gfx_set_palette(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, RGB(0,0,0), RGB(15,15,15), RGB(10,10,10), RGB(6,6,6));

    /* Debug cursor sprite palette: choose a palette slot you keep free in your assets. */
    ngpc_gfx_set_palette(GFX_SPR, (u8)NGPNG_AUTORUN_CURSOR_PAL, RGB(0,0,0), RGB(15,15,15), RGB(10,10,10), RGB(6,6,6));
    ngpc_sprite_hide_all();

    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 0, "NGPNG Autorun");
    print_scene_line(cur_scene);
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 3, "Demo scene runtime");
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 4, "OPT: next SFX");
#if defined(NGP_ENABLE_SOUND) && (NGP_ENABLE_SOUND)
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 5, "A: preview SFX");
#else
    ngpc_text_print(GFX_SCR1, (u8)NGPNG_AUTORUN_TEXT_PAL, 0, 5, "Sound: disabled");
#endif
    print_sfx_line(sfx_id);
    print_trig_line(0);
#endif /* NGPNG_AUTORUN_DEBUG_OVERLAY */

    while (1) {
        const NgpSceneDef *sc;
        u8 trig_n;
        u8 reg_n;
        u8 in_reg[NGPNG_AUTORUN_MAX_REG];
        u8 rj;
        u8 i;
        u8 cj;
        u8 ccount;
        u8 cstart;
        u8 all_ok;
        u8 requested_scene;
        u8 scene_changed;
        ngpc_vsync();
        ngpc_input_update();
        ngpc_sprite_frame_begin();
        sc = &g_ngp_scenes[cur_scene];

        /* ----------------------------------------------------------------
         * UPDATE -- follow the validated shmup pattern:
         * all gameplay + sprite shadow writes happen here, then VBlank ISR flushes.
         * ---------------------------------------------------------------- */
        scene_changed = 0;
        requested_scene = 0xFFu;
        player_jump_started = 0u;
        if ((game_over || stage_clear) && (ngpc_pad_pressed & PAD_B)) {
            u8 use_continue = 0u;
            if (game_over && continues_left > 0u) {
                continues_left = (u8)(continues_left - 1u);
                use_continue = 1u;
            }
            timer = 0;
            if (!use_continue) score = 0;
            collectible_count = 0u;
#if NGPNG_AUTORUN_SCORE_HUD
            flash_saved = 0u;
#endif
            sc->exit();
            sc->enter();
            cam_px = (s16)(sc->cam_tile_x * 8u);
            cam_py = (s16)(sc->cam_tile_y * 8u);
            ngpng_apply_camera_constraints(sc, &cam_px, &cam_py);
            ngpng_queue_plane_stream(sc, cam_px, cam_py);
            ngpng_apply_plane_scroll(sc, cam_px, cam_py);
            tx = (u16)(cam_px >> 3);
            ty = (u16)(cam_py >> 3);
            ngpng_fx_clear(fx, &fx_active_count, &fx_alloc_idx);
            ngpng_props_reset_scene(sc, props, &prop_count);
            player_form = 0u;
            player_form_mode = 0u;
            player_form_count = ngpng_count_types_by_role(sc, NGPNG_ROLE_PLAYER);
            player_ent_flags = ngpng_find_first_entity_flags_by_role(sc, NGPNG_ROLE_PLAYER);
            ngpng_player_apply_form(sc, player_form, &player_type, &player_hb_x, &player_hb_y, &player_hb_w, &player_hb_h, &player_body_x, &player_body_y, &player_body_w, &player_body_h, &player_render_off_x, &player_render_off_y, &player_frame_w, &player_frame_h, &player_hp, &player_hp_max, 1u);
            player_bullet_type = ngpng_find_first_type_by_role(sc, NGPNG_ROLE_ITEM);
            explosion_type = ngpng_find_first_type_by_role(sc, NGPNG_ROLE_PROP);
            player_bullet_ready = 0u;
            if (player_bullet_type != 0xFFu && ngpng_entity_sprite_info(sc, player_bullet_type, 0u, &player_bullet_tile, &player_bullet_pal, &player_bullet_flags, &player_bullet_ox, &player_bullet_oy)) player_bullet_ready = 1u;
            if (player_bullet_type != 0xFFu) {
                player_bullet_hb_x = ngpng_type_attack_s8(sc->attack_hitbox_x, sc->hitbox_x, sc->type_role_count, player_bullet_type, 0);
                player_bullet_hb_y = ngpng_type_attack_s8(sc->attack_hitbox_y, sc->hitbox_y, sc->type_role_count, player_bullet_type, 0);
                player_bullet_hb_w = ngpng_type_attack_u8(sc->attack_hitbox_w, sc->hitbox_w, sc->type_role_count, player_bullet_type, 8u);
                player_bullet_hb_h = ngpng_type_attack_u8(sc->attack_hitbox_h, sc->hitbox_h, sc->type_role_count, player_bullet_type, 8u);
                player_bullet_damage = ngpng_type_attack_u8(sc->attack_hitbox_damage, sc->type_damage, sc->type_role_count, player_bullet_type, 1u);
                player_bullet_kb_x = ngpng_type_attack_s8(sc->attack_hitbox_kb_x, 0, sc->type_role_count, player_bullet_type, 0);
                player_bullet_kb_y = ngpng_type_attack_s8(sc->attack_hitbox_kb_y, 0, sc->type_role_count, player_bullet_type, 0);
            }
            player_invul = 0u;
            game_over = 0u;
            stage_clear = 0u;
            lives = sc->start_lives;
            if (!use_continue) continues_left = sc->start_continues;
            respawn_timer = 0u;
            fire_cd = 0u;
            player_platform = 0xFFu;
            ngpc_sprite_hide_all();
            ngpng_hud_reset();
            ngpng_reset_trigger_state(s_trig_fired, s_trig_enabled, s_reg_prev);
            ngpng_reset_scene_scroll_state(sc, &runtime_forced_scroll, &runtime_scroll_paused, &runtime_scroll_speed_x, &runtime_scroll_speed_y);
            {
                s16 spawn_x;
                s16 spawn_y;
                ngpng_place_player_on_respawn(sc, (checkpoint_scene == cur_scene) ? checkpoint_region : 0xFFu, &cam_px, &cam_py, &spawn_x, &spawn_y);
                tx = (u16)(cam_px >> 3);
                ty = (u16)(cam_py >> 3);
                MAGICIAN_IDDLE_CTRL_INIT(s_magician_iddle, spawn_x, spawn_y);
                s_magician_iddle.flags = player_ent_flags;
                ngpng_player_clamp_world(sc, &s_magician_iddle, cam_px, cam_py, player_body_x, player_body_y, player_body_w, player_body_h, player_render_off_x, player_render_off_y, player_frame_w, player_frame_h);
                s_magician_iddle_visible = 0u;
                s_magician_iddle_last_x = (s16)-32768;
                s_magician_iddle_last_y = (s16)-32768;
                s_magician_iddle_last_frame = 0xFFu;
            }
        }
        sc->update();
        ngpng_props_update(sc, props, prop_count);
        /* ---- Player actor update ---- */
        if (!game_over && !stage_clear && respawn_timer == 0u) {
            s16 prev_player_world_x;
            s16 prev_player_world_y;
            s8 prev_player_vy;
            prev_player_world_x = (s16)(cam_px + s_magician_iddle.x);
            prev_player_world_y = (s16)(cam_py + s_magician_iddle.y);
            ngpng_player_apply_platform_delta(props, prop_count, player_platform, &s_magician_iddle.x, &s_magician_iddle.y);
            prev_player_world_x = (s16)(cam_px + s_magician_iddle.x);
            prev_player_world_y = (s16)(cam_py + s_magician_iddle.y);
            prev_player_vy = s_magician_iddle.vy;
            MAGICIAN_IDDLE_CTRL_UPDATE(s_magician_iddle);
            player_platform = ngpng_player_resolve_platforms(props, prop_count, prev_player_world_x, prev_player_world_y, cam_px, cam_py, &s_magician_iddle.x, &s_magician_iddle.y, &s_magician_iddle.vy, &s_magician_iddle.on_ground, &s_magician_iddle.coyote, player_body_x, player_body_y, player_body_w, player_body_h);
            ngpng_player_bump_blocks(sc, props, prop_count, prev_player_world_x, prev_player_world_y, cam_px, cam_py, &s_magician_iddle.x, &s_magician_iddle.y, &s_magician_iddle.vy, player_body_x, player_body_y, player_body_w, player_body_h, &score, &player_hp, player_hp_max, &collectible_count);
            ngpng_player_clamp_world(sc, &s_magician_iddle, cam_px, cam_py, player_body_x, player_body_y, player_body_w, player_body_h, player_render_off_x, player_render_off_y, player_frame_w, player_frame_h);
            if (s_magician_iddle.vy < 0 && prev_player_vy >= 0) player_jump_started = 1u;
            ngpng_player_apply_tile_effects(sc, (s16)(cam_px + s_magician_iddle.x), (s16)(cam_py + s_magician_iddle.y), player_body_x, player_body_y, player_body_w, player_body_h, &s_magician_iddle.vx, &s_magician_iddle.vy, &s_magician_iddle.on_ground, &s_magician_iddle.coyote, &player_hp, &player_invul);
            if (!runtime_forced_scroll) {
                s16 player_world_x = (s16)(cam_px + s_magician_iddle.x);
                s16 player_world_y = (s16)(cam_py + s_magician_iddle.y);
                s16 player_world_cx = (s16)(player_world_x + player_body_x + (player_body_w / 2u));
                s16 player_world_cy = (s16)(player_world_y + player_body_y + (player_body_h / 2u));
                ngpng_follow_player_camera(sc, player_world_cx, player_world_cy, &cam_px, &cam_py);
                ngpng_apply_camera_lock_region(sc, player_world_cx, player_world_cy, &cam_px, &cam_py);
                s_magician_iddle.x = (s16)(player_world_x - cam_px);
                s_magician_iddle.y = (s16)(player_world_y - cam_py);
            }
        }

        timer++;
        if (!game_over && !stage_clear && sc->time_limit_sec > 0u) {
            if (timer >= (u16)(sc->time_limit_sec * 60u)) game_over = 1u;
        }
        if (!game_over && !stage_clear && sc->goal_collectibles > 0u) {
            if (collectible_count >= sc->goal_collectibles) stage_clear = 1u;
        }
        if (!game_over && !stage_clear && respawn_timer > 0u) {
            respawn_timer = (u8)(respawn_timer - 1u);
            if (respawn_timer == 0u) {
                s16 spawn_x;
                s16 spawn_y;
                if (checkpoint_scene < (u8)NGP_SCENE_COUNT && checkpoint_scene != cur_scene) {
                    g_ngp_scenes[cur_scene].exit();
                    cur_scene = checkpoint_scene;
                    timer = 0u;
                    sc = &g_ngp_scenes[cur_scene];
                    g_ngp_scenes[cur_scene].enter();
                    cam_px = (s16)(sc->cam_tile_x * 8u);
                    cam_py = (s16)(sc->cam_tile_y * 8u);
                    ngpng_apply_camera_constraints(sc, &cam_px, &cam_py);
                    ngpng_queue_plane_stream(sc, cam_px, cam_py);
                    ngpng_apply_plane_scroll(sc, cam_px, cam_py);
                    tx = (u16)(cam_px >> 3);
                    ty = (u16)(cam_py >> 3);
                    ngpng_fx_clear(fx, &fx_active_count, &fx_alloc_idx);
                    ngpng_props_reset_scene(sc, props, &prop_count);
                    player_form = 0u;
                    player_form_mode = 0u;
                    player_form_count = ngpng_count_types_by_role(sc, NGPNG_ROLE_PLAYER);
                    player_ent_flags = ngpng_find_first_entity_flags_by_role(sc, NGPNG_ROLE_PLAYER);
                    ngpng_player_apply_form(sc, player_form, &player_type, &player_hb_x, &player_hb_y, &player_hb_w, &player_hb_h, &player_body_x, &player_body_y, &player_body_w, &player_body_h, &player_render_off_x, &player_render_off_y, &player_frame_w, &player_frame_h, &player_hp, &player_hp_max, 1u);
                    player_bullet_type = ngpng_find_first_type_by_role(sc, NGPNG_ROLE_ITEM);
                    explosion_type = ngpng_find_first_type_by_role(sc, NGPNG_ROLE_PROP);
                    player_bullet_ready = 0u;
                    if (player_bullet_type != 0xFFu && ngpng_entity_sprite_info(sc, player_bullet_type, 0u, &player_bullet_tile, &player_bullet_pal, &player_bullet_flags, &player_bullet_ox, &player_bullet_oy)) player_bullet_ready = 1u;
                    if (player_bullet_type != 0xFFu) {
                        player_bullet_hb_x = ngpng_type_attack_s8(sc->attack_hitbox_x, sc->hitbox_x, sc->type_role_count, player_bullet_type, 0);
                        player_bullet_hb_y = ngpng_type_attack_s8(sc->attack_hitbox_y, sc->hitbox_y, sc->type_role_count, player_bullet_type, 0);
                        player_bullet_hb_w = ngpng_type_attack_u8(sc->attack_hitbox_w, sc->hitbox_w, sc->type_role_count, player_bullet_type, 8u);
                        player_bullet_hb_h = ngpng_type_attack_u8(sc->attack_hitbox_h, sc->hitbox_h, sc->type_role_count, player_bullet_type, 8u);
                        player_bullet_damage = ngpng_type_attack_u8(sc->attack_hitbox_damage, sc->type_damage, sc->type_role_count, player_bullet_type, 1u);
                        player_bullet_kb_x = ngpng_type_attack_s8(sc->attack_hitbox_kb_x, 0, sc->type_role_count, player_bullet_type, 0);
                        player_bullet_kb_y = ngpng_type_attack_s8(sc->attack_hitbox_kb_y, 0, sc->type_role_count, player_bullet_type, 0);
                    }
                    collectible_count = 0u;
                    ngpc_sprite_hide_all();
                    ngpng_hud_reset();
                    ngpng_reset_trigger_state(s_trig_fired, s_trig_enabled, s_reg_prev);
                    ngpng_reset_scene_scroll_state(sc, &runtime_forced_scroll, &runtime_scroll_paused, &runtime_scroll_speed_x, &runtime_scroll_speed_y);
                }
                ngpng_place_player_on_respawn(sc, (checkpoint_scene == cur_scene) ? checkpoint_region : 0xFFu, &cam_px, &cam_py, &spawn_x, &spawn_y);
                tx = (u16)(cam_px >> 3);
                ty = (u16)(cam_py >> 3);
                player_hp = player_hp_max;
                player_invul = 30u;
                fire_cd = 0u;
                game_over = 0u;
                stage_clear = 0u;
                player_platform = 0xFFu;
                ngpng_fx_clear(fx, &fx_active_count, &fx_alloc_idx);
                MAGICIAN_IDDLE_CTRL_INIT(s_magician_iddle, spawn_x, spawn_y);
                s_magician_iddle.flags = player_ent_flags;
                ngpng_player_clamp_world(sc, &s_magician_iddle, cam_px, cam_py, player_body_x, player_body_y, player_body_w, player_body_h, player_render_off_x, player_render_off_y, player_frame_w, player_frame_h);
                s_magician_iddle_visible = 0u;
                s_magician_iddle_last_x = (s16)-32768;
                s_magician_iddle_last_y = (s16)-32768;
                s_magician_iddle_last_frame = 0xFFu;
            }
        }
        if (!game_over && !stage_clear && runtime_forced_scroll && !runtime_scroll_paused) {
            if (sc->scroll_x) cam_px = (s16)(cam_px + runtime_scroll_speed_x);
            if (sc->scroll_y) cam_py = (s16)(cam_py + runtime_scroll_speed_y);
        }
        ngpng_apply_camera_constraints(sc, &cam_px, &cam_py);
        /* Screen shake: offset display each frame while timer > 0. */
        if (shake_timer > 0u) {
            s16 _soff = (shake_timer & 1u) ? (s16)shake_amp : (s16)(-(s16)shake_amp);
            shake_timer = (u8)(shake_timer - 1u);
            ngpng_queue_plane_stream(sc, (s16)(cam_px + _soff), cam_py);
            ngpng_apply_plane_scroll(sc, (s16)(cam_px + _soff), cam_py);
        } else {
            ngpng_queue_plane_stream(sc, cam_px, cam_py);
            ngpng_apply_plane_scroll(sc, cam_px, cam_py);
        }
        tx = (u16)(cam_px >> 3);
        ty = (u16)(cam_py >> 3);
        if (player_invul > 0u) player_invul = (u8)(player_invul - 1u);
        ngpng_fx_update(sc, fx, &fx_active_count, cam_px, cam_py);
        ngpng_player_collect_items(sc, props, prop_count, (s16)(cam_px + s_magician_iddle.x), (s16)(cam_py + s_magician_iddle.y), player_hb_x, player_hb_y, player_hb_w, player_hb_h, &score, &player_hp, player_hp_max, &collectible_count);
        if (!stage_clear && player_hp == 0u) {
            if (sc->start_lives > 0u) {
                if (lives > 0u) lives = (u8)(lives - 1u);
                if (lives > 0u) {
                    if (respawn_timer == 0u) respawn_timer = 30u;
                } else {
                    game_over = 1u;
                }
            } else if (checkpoint_scene < (u8)NGP_SCENE_COUNT && checkpoint_region != 0xFFu) {
                if (respawn_timer == 0u) respawn_timer = 30u;
            } else {
                game_over = 1u;
            }
        }
#if NGPNG_AUTORUN_SCORE_HUD
        if (game_over && !flash_saved) {
            if (score > best_score) {
                u8 save_buf[8];
                best_score = score;
                save_buf[0] = 0xCAu; save_buf[1] = 0xFEu;
                save_buf[2] = 0x20u; save_buf[3] = 0x26u;
                save_buf[4] = (u8)(best_score >> 8);
                save_buf[5] = (u8)(best_score & 0xFFu);
                save_buf[6] = 0u; save_buf[7] = 0u;
                ngpc_flash_save(save_buf);
            }
            flash_saved = 1u;
        }
#endif
        if (player_hp > 0u && !(player_invul > 0u && (player_invul & 2u))) {
            if (player_form_mode) {
                u8 player_render_idx = (player_form < 1u) ? player_form : 0u;
                if (player_render_idx == 0u) ngpng_player_layer_sync((u8)((u8)NGPNG_AUTORUN_PLAYER_SPR_BASE + 0u), (s16)(s_magician_iddle.x + player_render_off_x), (s16)(s_magician_iddle.y + player_render_off_y), s_magician_iddle.frame, magician_iddle_anim, magician_iddle_anim_count, &s_magician_iddle_visible, &s_magician_iddle_last_x, &s_magician_iddle_last_y, &s_magician_iddle_last_frame);
                else { ngpng_sprite_hide_range((u8)((u8)NGPNG_AUTORUN_PLAYER_SPR_BASE + 0u), 4u); s_magician_iddle_visible = 0u; }
            } else {
                ngpng_player_layer_sync((u8)((u8)NGPNG_AUTORUN_PLAYER_SPR_BASE + 0u), (s16)(s_magician_iddle.x + player_render_off_x), (s16)(s_magician_iddle.y + player_render_off_y), s_magician_iddle.frame, magician_iddle_anim, magician_iddle_anim_count, &s_magician_iddle_visible, &s_magician_iddle_last_x, &s_magician_iddle_last_y, &s_magician_iddle_last_frame);
            }
        } else {
            ngpng_sprite_hide_range((u8)((u8)NGPNG_AUTORUN_PLAYER_SPR_BASE + 0u), 4u);
            s_magician_iddle_visible = 0u;
        }

#if NGPNG_AUTORUN_SCORE_HUD
        /* HUD/game state: running, game over, or stage clear. */
        if (game_over) ngpng_hud_sync(sc, sc->hud_flags, sc->hud_pos, sc->hud_font_mode, best_score, 0u, lives, continues_left, collectible_count, timer, 1u, 0u);
        else ngpng_hud_sync(sc, sc->hud_flags, sc->hud_pos, sc->hud_font_mode, score, player_hp, lives, continues_left, collectible_count, timer, 0u, stage_clear);
#endif
#if NGPNG_AUTORUN_DEBUG_OVERLAY
        /* Cursor reserved for overlay. */
        ngpc_sprite_set((u8)NGPNG_AUTORUN_CURSOR_SPR_SLOT, (u8)8, (u8)8, (u16)CUR_TILE, (u8)NGPNG_AUTORUN_CURSOR_PAL, (u8)SPR_FRONT);
#endif

#if defined(NGP_ENABLE_SOUND) && (NGP_ENABLE_SOUND)
#if (NGPNG_SFX_COUNT > 0u)
#if NGPNG_AUTORUN_DEBUG_OVERLAY
        if (ngpc_pad_pressed & PAD_OPTION) {
            sfx_id = (u8)((sfx_id + 1u) % (u8)NGPNG_SFX_COUNT);
            print_sfx_line(sfx_id);
        }
        if (ngpc_pad_pressed & PAD_A) {
            Sfx_Play(sfx_id);
        }
#endif
#endif
#endif

        /* Triggers (conditions -> actions) exported by the Level tab. */
        trig_n = sc->trigger_count;
        reg_n = sc->region_count;
        if (trig_n > (u8)NGPNG_AUTORUN_MAX_TRIG) trig_n = (u8)NGPNG_AUTORUN_MAX_TRIG;
        if (reg_n > (u8)NGPNG_AUTORUN_MAX_REG) reg_n = (u8)NGPNG_AUTORUN_MAX_REG;
        for (rj = 0; rj < reg_n; ++rj) {
            const NgpngRect *r = &sc->regions[rj];
            s16 sx = (s16)tx;
            s16 sy = (s16)ty;
            s16 rx0 = r->x;
            s16 ry0 = r->y;
            s16 rx1 = (s16)(r->x + r->w);
            s16 ry1 = (s16)(r->y + r->h);
            in_reg[rj] = (sx >= rx0) && (sy >= ry0) && (sx < rx1) && (sy < ry1);
        }
        if (!game_over && respawn_timer == 0u && sc->region_kind) {
            s16 player_world_x = (s16)(cam_px + s_magician_iddle.x + player_hb_x + (player_hb_w / 2u));
            s16 player_world_y = (s16)(cam_py + s_magician_iddle.y + player_hb_y + (player_hb_h / 2u));
            for (rj = 0; rj < reg_n; ++rj) {
                u8 next_scene;
                if (!ngpng_region_contains_world_point(sc, rj, player_world_x, player_world_y)) continue;
                if (sc->region_kind[rj] == REGION_KIND_CHECKPOINT) {
                    checkpoint_scene = cur_scene;
                    checkpoint_region = rj;
                } else if (sc->region_kind[rj] == REGION_KIND_EXIT_GOAL) {
                    next_scene = ngpng_region_goto_scene_target(sc, rj);
                    if (next_scene == 0xFFu) next_scene = (u8)(cur_scene + 1u);
                    if (next_scene < (u8)NGP_SCENE_COUNT) requested_scene = next_scene;
                    else stage_clear = 1u;
                }
            }
            if ((ngpc_pad_pressed & (PAD_UP | PAD_A)) && ngpng_player_touches_door_tile(sc, (s16)(cam_px + s_magician_iddle.x), (s16)(cam_py + s_magician_iddle.y), player_hb_x, player_hb_y, player_hb_w, player_hb_h)) {
                u8 next_scene = 0xFFu;
                for (rj = 0; rj < reg_n; ++rj) {
                    if (!ngpng_region_contains_world_point(sc, rj, player_world_x, player_world_y)) continue;
                    next_scene = ngpng_region_goto_scene_target(sc, rj);
                    if (next_scene != 0xFFu) break;
                }
                if (next_scene == 0xFFu) next_scene = (u8)(cur_scene + 1u);
                if (next_scene < (u8)NGP_SCENE_COUNT) requested_scene = next_scene;
                else stage_clear = 1u;
            }
        }
        for (i = 0; i < trig_n; ++i) {
            const NgpngTrigger *t = &sc->triggers[i];
            u8 fire = 0;
            if (t->once && s_trig_fired[i]) continue;
            if (!s_trig_enabled[i]) continue;
            fire = ngpng_trigger_cond_met(t->cond, t->region, t->value, in_reg, s_reg_prev, reg_n, tx, ty, timer, next_wave, player_hp, lives, enemy_active_count, collectible_count, ngpc_pad_pressed, player_jump_started);
            if (fire && sc->trig_conds && sc->trig_cond_count && sc->trig_cond_start) {
                ccount = sc->trig_cond_count[i];
                cstart = sc->trig_cond_start[i];
                all_ok = 1u;
                for (cj = 0; cj < ccount; ++cj) {
                    const NgpngCond *ec = &sc->trig_conds[(u8)(cstart + cj)];
                    if (!ngpng_trigger_cond_met(ec->cond, ec->region, ec->value, in_reg, s_reg_prev, reg_n, tx, ty, timer, next_wave, player_hp, lives, enemy_active_count, collectible_count, ngpc_pad_pressed, player_jump_started)) {
                        all_ok = 0u;
                        break;
                    }
                }
                if (!all_ok) fire = 0u;
            }
            if (!fire) continue;
            if (t->once) s_trig_fired[i] = 1;
#if NGPNG_AUTORUN_DEBUG_OVERLAY
            print_trig_line(i);
#endif
#if defined(NGP_ENABLE_SOUND) && (NGP_ENABLE_SOUND)
            if (t->action == TRIG_ACT_PLAY_SFX) {
                Sfx_Play(t->a0);
            } else if (t->action == TRIG_ACT_FADE_BGM) {
                Bgm_FadeOut(t->a0);
            } else if (t->action == TRIG_ACT_STOP_BGM) {
                Bgm_Stop();
            } else if (t->action == TRIG_ACT_START_BGM) {
#if (NGPNG_SONG_COUNT > 0)
                if (t->a0 < (u8)NGPNG_SONG_COUNT) NgpcProject_BgmStartLoop4ByIndex(t->a0);
#endif
            }
#endif
            if (t->action == TRIG_ACT_ADD_SCORE) {
                score = (u16)(score + ((u16)t->a0 * 10u));
            }
            if (t->action == TRIG_ACT_PAUSE_SCROLL) {
                runtime_scroll_paused = 1u;
            }
            if (t->action == TRIG_ACT_RESUME_SCROLL) {
                runtime_forced_scroll = 1u;
                runtime_scroll_paused = 0u;
            }
            if (t->action == TRIG_ACT_SET_SCROLL_SPEED) {
                runtime_forced_scroll = 1u;
                runtime_scroll_paused = 0u;
                runtime_scroll_speed_x = (s16)t->a0;
                runtime_scroll_speed_y = (s16)t->a1;
            }
            if (t->action == TRIG_ACT_PLAY_ANIM) {
                ngpng_props_set_anim_by_type(props, prop_count, t->a0, t->a1);
            }
            if (t->action == TRIG_ACT_ENABLE_TRIGGER) {
                if (t->a0 < trig_n) s_trig_enabled[t->a0] = 1u;
            }
            if (t->action == TRIG_ACT_DISABLE_TRIGGER) {
                if (t->a0 < trig_n) s_trig_enabled[t->a0] = 0u;
            }
            if (t->action == TRIG_ACT_SHOW_ENTITY) {
                u8 pi;
                pi = ngpng_prop_find_by_src(props, prop_count, t->a0);
                if (pi != 0xFFu) props[pi].visible = 1u;
            }
            if (t->action == TRIG_ACT_HIDE_ENTITY) {
                u8 pi;
                pi = ngpng_prop_find_by_src(props, prop_count, t->a0);
                if (pi != 0xFFu) props[pi].visible = 0u;
            }
            if (t->action == TRIG_ACT_MOVE_ENTITY_TO) {
                u8 pi;
                pi = ngpng_prop_find_by_src(props, prop_count, t->a0);
                if (pi != 0xFFu && t->a1 < reg_n) {
                    const NgpngRect *dst;
                    dst = &sc->regions[t->a1];
                    props[pi].target_x = (s16)(dst->x * 8);
                    props[pi].target_y = (s16)(dst->y * 8);
                    props[pi].moving = 1u;
                    props[pi].visible = 1u;
                }
            }
            if (t->action == TRIG_ACT_PAUSE_ENTITY_PATH) {
                u8 pi;
                pi = ngpng_prop_find_by_src(props, prop_count, t->a0);
                if (pi != 0xFFu) props[pi].paused = 1u;
            }
            if (t->action == TRIG_ACT_RESUME_ENTITY_PATH) {
                u8 pi;
                pi = ngpng_prop_find_by_src(props, prop_count, t->a0);
                if (pi != 0xFFu && props[pi].path_idx != 0xFFu) props[pi].paused = 0u;
            }
            if (t->action == 15u) { /* screen_shake */
                shake_amp   = (u8)(t->a0 ? t->a0 : 2u); /* a0=amplitude px */
                shake_timer = (u8)(t->a1 ? t->a1 : 8u); /* a1=durée frames */
            }
            if (t->action == TRIG_ACT_SET_CAM_TARGET) {
                cam_px = (s16)(t->a0 * 8u);
                cam_py = (s16)(t->a1 * 8u);
                ngpng_apply_camera_constraints(sc, &cam_px, &cam_py);
                ngpng_queue_plane_stream(sc, cam_px, cam_py);
                ngpng_apply_plane_scroll(sc, cam_px, cam_py);
                tx = (u16)(cam_px >> 3);
                ty = (u16)(cam_py >> 3);
            }
            if (t->action == TRIG_ACT_CYCLE_PLAYER_FORM) {
                if (player_form_count > 0u) {
                    player_form = (u8)((player_form + 1u) % player_form_count);
                    player_form_mode = 1u;
                    ngpng_player_apply_form(sc, player_form, &player_type, &player_hb_x, &player_hb_y, &player_hb_w, &player_hb_h, &player_body_x, &player_body_y, &player_body_w, &player_body_h, &player_render_off_x, &player_render_off_y, &player_frame_w, &player_frame_h, &player_hp, &player_hp_max, 0u);
                }
            }
            if (t->action == TRIG_ACT_SET_PLAYER_FORM) {
                if (player_form_count > 0u) {
                    player_form = (u8)(t->a0 % player_form_count);
                    player_form_mode = 1u;
                    ngpng_player_apply_form(sc, player_form, &player_type, &player_hb_x, &player_hb_y, &player_hb_w, &player_hb_h, &player_body_x, &player_body_y, &player_body_w, &player_body_h, &player_render_off_x, &player_render_off_y, &player_frame_w, &player_frame_h, &player_hp, &player_hp_max, 0u);
                }
            }
            if (t->action == TRIG_ACT_SET_CHECKPOINT) {
                if (t->region < reg_n) {
                    checkpoint_scene = cur_scene;
                    checkpoint_region = t->region;
                }
            }
            if (t->action == TRIG_ACT_RESPAWN_PLAYER) {
                s16 spawn_x;
                s16 spawn_y;
                ngpng_place_player_on_respawn(sc, (checkpoint_scene == cur_scene) ? checkpoint_region : 0xFFu, &cam_px, &cam_py, &spawn_x, &spawn_y);
                tx = (u16)(cam_px >> 3);
                ty = (u16)(cam_py >> 3);
                player_hp = player_hp_max;
                player_invul = 30u;
                fire_cd = 0u;
                game_over = 0u;
                stage_clear = 0u;
                if (sc->start_lives > 0u && lives == 0u) lives = sc->start_lives;
                respawn_timer = 0u;
                player_platform = 0xFFu;
                ngpng_fx_clear(fx, &fx_active_count, &fx_alloc_idx);
                MAGICIAN_IDDLE_CTRL_INIT(s_magician_iddle, spawn_x, spawn_y);
                s_magician_iddle.flags = player_ent_flags;
                ngpng_player_clamp_world(sc, &s_magician_iddle, cam_px, cam_py, player_body_x, player_body_y, player_body_w, player_body_h, player_render_off_x, player_render_off_y, player_frame_w, player_frame_h);
                s_magician_iddle_visible = 0u;
                s_magician_iddle_last_x = (s16)-32768;
                s_magician_iddle_last_y = (s16)-32768;
                s_magician_iddle_last_frame = 0xFFu;
            }
            if (t->action == TRIG_ACT_GOTO_SCENE) {
                u8 next = t->a0;
                if (next < (u8)NGP_SCENE_COUNT && next != cur_scene) {
                    requested_scene = next;
                    break;
                }
            }
            if (t->action == TRIG_ACT_SET_FLAG) {
                if (t->a0 < NGPNG_FLAG_COUNT) s_ngpng_flags[t->a0] = 1u;
            }
            if (t->action == TRIG_ACT_CLEAR_FLAG) {
                if (t->a0 < NGPNG_FLAG_COUNT) s_ngpng_flags[t->a0] = 0u;
            }
            if (t->action == TRIG_ACT_SET_VARIABLE) {
                if (t->a0 < NGPNG_VAR_COUNT) s_ngpng_vars[t->a0] = t->a1;
            }
            if (t->action == TRIG_ACT_INC_VARIABLE) {
                if (t->a0 < NGPNG_VAR_COUNT) {
                    /* a1=0 means no cap; otherwise cap at a1 */
                    if (t->a1 == 0u || s_ngpng_vars[t->a0] < t->a1) s_ngpng_vars[t->a0]++;
                }
            }
        }
        if (!scene_changed && requested_scene < (u8)NGP_SCENE_COUNT && requested_scene != cur_scene) {
            g_ngp_scenes[cur_scene].exit();
            cur_scene = requested_scene;
            timer = 0;
            sc = &g_ngp_scenes[cur_scene];
            g_ngp_scenes[cur_scene].enter();
            cam_px = (s16)(sc->cam_tile_x * 8u);
            cam_py = (s16)(sc->cam_tile_y * 8u);
            ngpng_apply_camera_constraints(sc, &cam_px, &cam_py);
            ngpng_queue_plane_stream(sc, cam_px, cam_py);
            ngpng_apply_plane_scroll(sc, cam_px, cam_py);
            tx = (u16)(cam_px >> 3);
            ty = (u16)(cam_py >> 3);
            ngpng_fx_clear(fx, &fx_active_count, &fx_alloc_idx);
            ngpng_props_reset_scene(sc, props, &prop_count);
            player_form = 0u;
            player_form_mode = 0u;
            player_form_count = ngpng_count_types_by_role(sc, NGPNG_ROLE_PLAYER);
            player_ent_flags = ngpng_find_first_entity_flags_by_role(sc, NGPNG_ROLE_PLAYER);
            ngpng_player_apply_form(sc, player_form, &player_type, &player_hb_x, &player_hb_y, &player_hb_w, &player_hb_h, &player_body_x, &player_body_y, &player_body_w, &player_body_h, &player_render_off_x, &player_render_off_y, &player_frame_w, &player_frame_h, &player_hp, &player_hp_max, 1u);
            player_bullet_type = ngpng_find_first_type_by_role(sc, NGPNG_ROLE_ITEM);
            explosion_type = ngpng_find_first_type_by_role(sc, NGPNG_ROLE_PROP);
            player_bullet_ready = 0u;
            if (player_bullet_type != 0xFFu && ngpng_entity_sprite_info(sc, player_bullet_type, 0u, &player_bullet_tile, &player_bullet_pal, &player_bullet_flags, &player_bullet_ox, &player_bullet_oy)) player_bullet_ready = 1u;
            if (player_bullet_type != 0xFFu) {
                player_bullet_hb_x = ngpng_type_attack_s8(sc->attack_hitbox_x, sc->hitbox_x, sc->type_role_count, player_bullet_type, 0);
                player_bullet_hb_y = ngpng_type_attack_s8(sc->attack_hitbox_y, sc->hitbox_y, sc->type_role_count, player_bullet_type, 0);
                player_bullet_hb_w = ngpng_type_attack_u8(sc->attack_hitbox_w, sc->hitbox_w, sc->type_role_count, player_bullet_type, 8u);
                player_bullet_hb_h = ngpng_type_attack_u8(sc->attack_hitbox_h, sc->hitbox_h, sc->type_role_count, player_bullet_type, 8u);
                player_bullet_damage = ngpng_type_attack_u8(sc->attack_hitbox_damage, sc->type_damage, sc->type_role_count, player_bullet_type, 1u);
                player_bullet_kb_x = ngpng_type_attack_s8(sc->attack_hitbox_kb_x, 0, sc->type_role_count, player_bullet_type, 0);
                player_bullet_kb_y = ngpng_type_attack_s8(sc->attack_hitbox_kb_y, 0, sc->type_role_count, player_bullet_type, 0);
            }
            player_invul = 0u;
            game_over = 0u;
            stage_clear = 0u;
            lives = sc->start_lives;
            fire_cd = 0u;
            player_platform = 0xFFu;
            collectible_count = 0u;
            ngpc_sprite_hide_all();
            ngpng_hud_reset();
            ngpng_reset_trigger_state(s_trig_fired, s_trig_enabled, s_reg_prev);
            ngpng_reset_scene_scroll_state(sc, &runtime_forced_scroll, &runtime_scroll_paused, &runtime_scroll_speed_x, &runtime_scroll_speed_y);
            {
                s16 spawn_x;
                s16 spawn_y;
                ngpng_place_player_on_respawn(sc, 0xFFu, &cam_px, &cam_py, &spawn_x, &spawn_y);
                tx = (u16)(cam_px >> 3);
                ty = (u16)(cam_py >> 3);
                MAGICIAN_IDDLE_CTRL_INIT(s_magician_iddle, spawn_x, spawn_y);
                s_magician_iddle.flags = player_ent_flags;
                ngpng_player_clamp_world(sc, &s_magician_iddle, cam_px, cam_py, player_body_x, player_body_y, player_body_w, player_body_h, player_render_off_x, player_render_off_y, player_frame_w, player_frame_h);
                s_magician_iddle_visible = 0u;
                s_magician_iddle_last_x = (s16)-32768;
                s_magician_iddle_last_y = (s16)-32768;
                s_magician_iddle_last_frame = 0xFFu;
            }
#if NGPNG_AUTORUN_DEBUG_OVERLAY
            print_scene_line(cur_scene);
#endif
            scene_changed = 1;
        }
        if (!scene_changed) {
            for (rj = 0; rj < reg_n; ++rj) s_reg_prev[rj] = in_reg[rj];
            ngpng_props_draw(sc, props, prop_count, cam_px, cam_py);
        }
        ngpc_sprite_frame_end();
    }
}
